import React, { useState, useEffect, useRef } from 'react';
import Psd from '@webtoon/psd';
import imagePSD from '../img/layeredpots.psd';

export default function PsdFloatingController() {
  const [layers, setLayers] = useState([]);
  const [psdWidth, setPsdWidth] = useState(0);
  const [psdHeight, setPsdHeight] = useState(0);
  const [loading, setLoading] = useState(true);
  const [isolatedLayerId, setIsolatedLayerId] = useState(null);

  useEffect(() => {
    async function loadPsd() {
      try {
        const response = await fetch(imagePSD);
        const buffer = await response.arrayBuffer();
        const psd = Psd.parse(buffer);
        
        setPsdWidth(psd.width);
        setPsdHeight(psd.height);

        const parsedLayers = await Promise.all(
          psd.layers.map(async (layer, index) => {
            const pixelData = await layer.composite();
            
            // Extract out name metadata structure
            const rawName = layer.name || `Layer ${index}`;
            let cleanName = rawName;
            let price = 0;
            let description = "";

            if (rawName.includes('|')) {
              const parts = rawName.split('|');
              cleanName = parts[0].trim();
              price = parts[1].trim();
              description = parts[2].trim();
            }

            return {
              id: index,
              name: cleanName,
              price: price,
              description: description,
              width: layer.width,
              height: layer.height,
              left: layer.left,
              top: layer.top,
              pixelData: pixelData,
            };
          })
        );

        setLayers(parsedLayers.reverse());
      } catch (e) {
        console.error("Failed to parse resource layout:", e);
      } finally {
        setLoading(false);
      }
    }
    loadPsd();
  }, []);

  useEffect(() => {
    layers.forEach((layer) => {
      const canvas = document.getElementById(`layer-${layer.id}`);
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      const imageData = new ImageData(
        new Uint8ClampedArray(layer.pixelData.buffer),
        layer.width,
        layer.height
      );
      ctx.putImageData(imageData, 0, 0);
    });
  }, [layers]);

  // Find target coordinates data matching active user click selections
  const selectedLayer = layers.find(l => l.id === isolatedLayerId);

  if (loading) return <div className="p-6 text-center text-gray-400">Loading scene modules...</div>;

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-slate-950 min-h-screen font-sans">
      
      {/* Absolute Staging Frame Canvas Area */}
      <div 
        className="relative bg-transparent shadow-2xl rounded overflow-visible select-none border border-slate-800"
        style={{ width: `${psdWidth}px`, height: `${psdHeight}px` }}
        onClick={() => setIsolatedLayerId(null)}
      >
        {layers.map((layer) => {
          const isSelected = isolatedLayerId === layer.id;
          const shouldBlurThisLayer = isolatedLayerId !== null && !isSelected;
          const isLayerZero = layer.id === 0;

          return (
            <canvas
              key={layer.id}
              id={`layer-${layer.id}`}
              width={layer.width}
              height={layer.height}
              onClick={(e) => {
                if (isLayerZero) return; 
                e.stopPropagation(); 
                setIsolatedLayerId(isSelected ? null : layer.id);
              }}
              className="absolute transition-all duration-500 ease-out"
              style={{ 
                left: `${layer.left}px`, 
                top: `${layer.top}px`,
                pointerEvents: isLayerZero ? 'none' : 'auto', 
                cursor: isLayerZero ? 'default' : 'pointer',
                zIndex: isSelected ? 40 : layer.id,
                transformOrigin: 'center center',
                transform: isSelected ? 'scale(1.08)' : 'scale(1)',
                filter: shouldBlurThisLayer 
                  ? 'blur(16px) brightness(35%) contrast(85%)' 
                  : 'blur(0px) brightness(100%) contrast(100%)',
              }}
            />
          );
        })}

        {/* 
          Floating Target Metadata Div:
          Appears instantly beside the selected object canvas layout coordinates.
        */}
        {selectedLayer && (
          <div
            className="absolute p-2.5 bg-white text-slate-900 rounded-lg shadow-2xl z-50 pointer-events-none transition-all duration-300 ease-out whitespace-nowrap"
            style={{
            // 1. Horizontal Centering: Position at the layer's horizontal midpoint
            left: `${selectedLayer.left + (selectedLayer.width / 2)}px`,
            
            // 2. Vertical Placement: Position 12px above the top edge of the layer
            top: `${selectedLayer.top - 12}px`,
            
            // 3. Alignment Adjustment: Shifts the label left by 50% of its own width and pulls it completely above the top coordinate
            transform: 'translate(-50%, -100%)',
            }}
          >
            {/* Tiny Indicator Arrow Pointer pointing to the layer */}
            <div className="absolute w-2 h-2 bg-white rotate-45 bottom-[-4px] left-1/2 -translate-x-1/2 shadow-md" />
    
            <div className="relative z-10">
              <h4 className="text-sm text-slate-900">$ {selectedLayer.price}</h4>
              <h4 className="w-full text-center font-bold text-sm text-slate-900">{selectedLayer.name}</h4>
              {selectedLayer.description && (
                <p className="text-center text-wrap text-xs text-slate-500 mt-0.5 font-normal max-w-[200px] whitespace-normal">
                  {selectedLayer.description}
                </p>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}