export const fetchDocuments = async (params = {}) => {
  const queryParams = new URLSearchParams({ ...params, group_by: 'contract' });
  const url = `${API_BASE_URL}/documents/?${queryParams.toString()}`;
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error('Failed to fetch documents');
  }
  return response.json();
};

export const fetchContractDocuments = async (contractId) => {
  return fetchDocuments({ contract: contractId });
};

