export const getDocumentViewUrl = (doc) => {
  if (!doc || !doc.file_path) return '';
  if (doc.file_path.startsWith('http')) {
    return doc.file_path;
  }
  return `${MEDIA_BASE_URL}${doc.file_path}`;
};

