export const changePassword = async ({ username, old_password, new_password, renew_password }) => {
  const body = new URLSearchParams();
  body.append('username', username);
  body.append('old_password', old_password);
  body.append('new_password', new_password);
  body.append('renew_password', renew_password);
  body.append('cur_path', window.location.pathname);

  const csrfToken = Cookies.get('csrftoken');
  const response = await fetch(`${API_BASE_URL}/change-password/`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded',
               'X-CSRFToken': csrfToken || ''
     },
    body: body.toString(),
    credentials: 'include',
  });

  if (!response.ok) {
    throw new Error('Failed to change password');
  }

  return response;
};

export const useContractModal = () => {
  const { openModal, closeModal } = useModal('contract');

  const openContractModal = (onSuccess) => {
    openModal('contract', async (data, files, docType) => {
      try {
        await createContract(data, files, docType);
        alert('Contract created successfully!');
        closeModal();
        if (onSuccess) {
          onSuccess();
        }
      } catch (error) {
        console.error('Error:', error);
        alert('Error creating contract');
      }
    }, { mode: 'create' });
  };

  const openViewContractModal = (contract) => {
    openModal('contract', null, { mode: 'view', initialData: contract });
  };

  const openEditContractModal = (contract, onSuccess) => {
    openModal('contract', async (data, files, docType) => {
      try {
        await updateContract(contract.id, data, files, docType);
        alert('Contract updated successfully!');
        closeModal();
        onSuccess && onSuccess();
      } catch (error) {
        console.error('Error:', error);
        alert('Error updating contract');
      }
    }, { mode: 'edit', initialData: contract });
  };

  return { openContractModal, openViewContractModal, openEditContractModal };
};



