import React, { useState, useEffect } from 'react';
import { Icon } from '../components/icons';


import { useDocumentViewModal, fetchDocuments as fetchDocumentsApi, getContractTypes, deleteDocument, getDocumentViewUrl } from '../services/api';

const formatFileSize = (bytes) => {
  if (!bytes || bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
};

const formatDate = (isoString) => {
  if (!isoString) return '-';
  const date = new Date(isoString);
  return date.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
};

const useDebounce = (value, delay) => {
  const [debouncedValue, setDebouncedValue] = useState(value);
  useEffect(() => {
    const handler = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(handler);
  }, [value, delay]);
  return debouncedValue;
};

const FILE_TYPE_OPTIONS = [
  { value: 'all', label: 'All File Types' },
  { value: 'image', label: 'Image' },
  { value: 'pdf', label: 'PDF' },
  { value: 'word', label: 'Word Document' },
  { value: 'excel', label: 'Excel' },
  { value: 'powerpoint', label: 'PowerPoint' },
  { value: 'text', label: 'Text' },
  { value: 'other', label: 'Other' },
];

const Documents = ({ initialConfig, onConfigChange }) => {
  const config = { 
    filterType: initialConfig?.filterType || 'all', 
    fileType: initialConfig?.fileType || 'all', 
    searchQuery: initialConfig?.searchQuery || '',
    sortConfig: initialConfig?.sortConfig || { key: 'uploaded_at', direction: 'desc' }
  };

  const { openDocumentViewerModal } = useDocumentViewModal();
  const [groups, setGroups] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [error, setError] = useState('');
  const [searchQuery, setSearchQuery] = useState(config.searchQuery);
  const [filterType, setFilterType] = useState(config.filterType);
  const [fileType, setFileType] = useState(config.fileType);
  const [sortConfig, setSortConfig] = useState(config.sortConfig);
  const [contractTypes, setContractTypes] = useState([]);
  const [hasMore, setHasMore] = useState(false);
  const debouncedSearch = useDebounce(searchQuery, 500);

  // Fetch params state (combines all params for the API call)
  const [fetchParams, setFetchParams] = useState({
    offset: 0,
    search: config.searchQuery,
    contract_type: config.filterType,
    file_type: config.fileType,
    sort_by: config.sortConfig.key,
    sort_order: config.sortConfig.direction
  });

  // Track whether state changes are from user interaction (not from initialConfig)
  const onConfigChangeRef = React.useRef(onConfigChange);
  onConfigChangeRef.current = onConfigChange;
  const isUserDriven = React.useRef(false);

  // Save config changes to parent whenever user-driven state changes
  useEffect(() => {
    if (!isUserDriven.current) {
      // First render: state was set from initialConfig, mark as user-driven going forward
      isUserDriven.current = true;
      return;
    }
    // User changed something, notify parent
    onConfigChangeRef.current?.({
      filterType,
      fileType,
      searchQuery,
      sortConfig
    });
  }, [filterType, fileType, searchQuery, sortConfig]);

  // Fetch contract types for dropdown on mount
  useEffect(() => {
    const loadContractTypes = async () => {
      try {
        const types = await getContractTypes();
        setContractTypes(types);
      } catch (err) {
        console.error('Failed to load contract types:', err);
      }
    };
    loadContractTypes();
  }, []);

  // Update fetchParams when filters change (reset offset to 0)
  useEffect(() => {
    setFetchParams({
      offset: 0,
      search: debouncedSearch,
      contract_type: filterType,
      file_type: fileType,
      sort_by: sortConfig.key,
      sort_order: sortConfig.direction
    });
  }, [debouncedSearch, filterType, fileType, sortConfig]);

  // Fetch documents whenever fetchParams changes
  useEffect(() => {
    const doFetch = async () => {
      const isInitial = fetchParams.offset === 0;
      if (isInitial) setLoading(true);
      else setLoadingMore(true);

      try {
        const params = {
          limit: 10,
          offset: fetchParams.offset,
          ...(fetchParams.search && { search: fetchParams.search }),
          ...(fetchParams.contract_type !== 'all' && { contract_type: fetchParams.contract_type }),
          ...(fetchParams.file_type !== 'all' && { file_type: fetchParams.file_type }),
          sort_by: fetchParams.sort_by,
          sort_order: fetchParams.sort_order
        };

        const data = await fetchDocumentsApi(params);
        if (isInitial) {
          setGroups(data.results);
        } else {
          setGroups(prev => [...prev, ...data.results]);
        }
        setHasMore(data.has_more);
        setError('');
      } catch (err) {
        if (isInitial) setError(err.message);
      } finally {
        if (isInitial) setLoading(false);
        else setLoadingMore(false);
      }
    };

    doFetch();
  }, [fetchParams]);

  const handleLoadMore = () => {
    setFetchParams(prev => ({
      ...prev,
      offset: groups.length
    }));
  };

  const handleSort = (key) => {
    setSortConfig((prev) => {
      if (prev.key === key) {
        return { key, direction: prev.direction === 'asc' ? 'desc' : 'asc' };
      }
      return { key, direction: 'asc' };
    });
  };

  const getSortIcon = (key) => {
    const iconClass = 'w-3 h-3 inline';
    if (sortConfig.key !== key) {
      return (
        <svg className={`${iconClass} opacity-40`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4-4" />
        </svg>
      );
    }
    return sortConfig.direction === 'asc' ? (
      <svg className={iconClass} fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" />
      </svg>
    ) : (
      <svg className={iconClass} fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
      </svg>
    );
  };
  
  const isViewable = (doc) => doc?.mime_type?.startsWith('image/') || doc?.mime_type === 'application/pdf';

  const statusColors = {
    active: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/50 dark:text-emerald-200',
    inactive: 'bg-amber-100 text-amber-800 dark:bg-amber-900/50 dark:text-amber-200',
    expired: 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-200',
  };


  const SortHeader = ({ label, sortKey, align = 'left' }) => (
    <th
      className={`px-6 py-4 text-${align} font-bold text-white uppercase tracking-wider cursor-pointer hover:bg-purple-700/60 hover:shadow-xl transition-colors select-none`}
      onClick={() => handleSort(sortKey)}
    >
      <div className={`inline-flex items-center relative ${align === 'center' ? 'justify-center' : ''}`}>
        <span>{label}</span>
        <span className="absolute left-full ml-1">{getSortIcon(sortKey)}</span>
      </div>
    </th>
  );

  // const handleViewDocument = (doc) => {
  //   if (doc.mime_type?.startsWith('image/') || doc.mime_type === 'application/pdf') {
  //     openDocumentViewerModal((doc) => setFetchParams(prev => ({ ...prev, offset: 0 })));
  //   } else {
  //     handleDownloadDocument(doc);
  //   }
  // };

  const handleDownloadDocument = (doc) => {
    const url = getDocumentViewUrl(doc);
    if (!url) return;
    window.open(url, '_blank');
  };

  const handleDeleteDocument = async (doc) => {
    if (!window.confirm(`Are you sure you want to delete "${doc.original_filename || doc.document_name}"?`)) return;
    try {
      await deleteDocument(doc.id);
      setGroups(prev => prev
        .map(group => ({
          ...group,
          documents: group.documents.filter(d => d.id !== doc.id)
        }))
        .filter(group => group.documents.length > 0)
      );
    } catch (err) {
      console.error('Failed to delete document:', err);
      alert('Failed to delete document');
    }
  };

  const hasActiveFilters = debouncedSearch || filterType !== 'all' || fileType !== 'all';

  return (
    <div className="space-y-6">

      {/* Search & Filter Bar */}
      <div className="flex flex-col lg:flex-row gap-4">
        <div className="relative flex-1">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
          <input
            type="text"
            placeholder="Search documents..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 dark:border-slate-600 rounded-xl leading-5 bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm transition-colors"
          />
        </div>
        <select
          value={filterType}
          onChange={(e) => setFilterType(e.target.value)}
          className="block w-full lg:w-56 pl-3 pr-10 py-2.5 border border-gray-200 dark:border-slate-600 rounded-xl leading-5 bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm transition-colors cursor-pointer"
        >
          <option value="all">All Contract Types</option>
          {contractTypes.map((type) => (
            <option key={type.id} value={type.name}>{type.name}</option>
          ))}
        </select>
        <select
          value={fileType}
          onChange={(e) => setFileType(e.target.value)}
          className="block w-full lg:w-48 pl-3 pr-10 py-2.5 border border-gray-200 dark:border-slate-600 rounded-xl leading-5 bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm transition-colors cursor-pointer"
        >
          {FILE_TYPE_OPTIONS.map((option) => (
            <option key={option.value} value={option.value}>{option.label}</option>
          ))}
        </select>
        
        <button
          onClick={() => {
            setSearchQuery('');
            setFilterType('all');
            setFileType('all');
          }}
          className={`flex gap-1 bg-gradient-to-r from-indigo-500 to-purple-600 hover:from-indigo-600 hover:to-purple-700 text-white py-3 px-3 text-xs font-bold rounded-2xl shadow-lg hover:shadow-xl transition-all duration-200 ${!hasActiveFilters && 'opacity-50 cursor-not-allowed'}`}
          disabled={!hasActiveFilters}
        >
          <Icon name="filterFilled" className="w-4 h-4" />
          <span>Clear Filters</span>
        </button>
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-gray-200 dark:border-slate-700 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="bg-gradient-to-r from-indigo-500 to-indigo-800 text-white border-b border-gray-200 dark:border-slate-600">
                <th className="px-6 py-4 text-center font-bold text-white uppercase tracking-wider">
                  #
                </th>
                <SortHeader label="File Name" sortKey="document_name" align="left" />
                <SortHeader label="Contract" sortKey="contract_number" align="center" />
                <SortHeader label="Contract Type" sortKey="contract_type" align="center" />
                <SortHeader label="Size" sortKey="file_size" align="center" />
                <SortHeader label="Uploaded" sortKey="uploaded_at" align="center" />
                <th className="px-6 py-4 text-center font-bold text-white uppercase tracking-wider">
                  Type
                </th>
                <th className="px-6 py-4 text-center font-bold text-white uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-slate-700">
              {loading ? (
                <tr>
                  <td className="px-6 py-8 text-sm text-gray-600 dark:text-slate-400 text-center" colSpan="8">
                    <div className="flex items-center justify-center space-x-2">
                      <svg className="animate-spin h-5 w-5 text-indigo-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      <span>Loading documents...</span>
                    </div>
                  </td>
                </tr>
              ) : error ? (
                <tr>
                  <td className="px-6 py-8 text-sm text-red-500 text-center" colSpan="8">
                    Error: {error}
                  </td>
                </tr>
              ) : groups.length === 0 ? (
                <tr>
                  <td className="px-6 py-8 text-sm text-gray-600 dark:text-slate-400 text-center" colSpan="8">
                    {hasActiveFilters ? 'No documents match your search' : 'No documents uploaded yet'}
                  </td>
                </tr>
              ) : (
                <>{(() => {
                    let count = 0;
                    return groups.map((group) => (
                      <React.Fragment key={group.contract_number}>
                        {/* Contract Group Header */}
                        <tr className="bg-gradient-to-r from-indigo-500/30 to-blue-600/30 dark:text-white">
                          <td colSpan="8" className="px-6 py-3">
                            <div className="flex items-center justify-between">
                              <div className="flex items-center space-x-4">
                                <span className="font-bold text-lg">{group.contract_number || 'N/A'}</span>
                                <span className="bg-white/20 px-2 py-1 rounded text-sm font-semibold">{group.contract_type || 'N/A'}</span>
                                <span className={`px-3 py-1 rounded-full text-xs font-semibold ${statusColors[group.contract_status?.toLowerCase()] || 'bg-gray-100 text-gray-800 dark:bg-slate-700 dark:text-slate-300'}`}>
                                  {group.contract_status?.toUpperCase() || 'UNKNOWN'}
                                </span>
                              </div>
                              <span className="text-sm text-slate-800 dark:text-blue-100">{group.documents.length} document{group.documents.length !== 1 ? 's' : ''}</span>
                            </div>
                          </td>
                        </tr>
                        {/* Documents */}
                        {(group.documents || []).map((doc) => {
                          count++;
                          return (
                            <tr key={doc.id} className="hover:bg-gray-50 dark:hover:bg-slate-700/50 transition-colors border-l-4 border-blue-200 dark:border-blue-800">
                              <td className="px-6 py-4 text-center text-gray-400 dark:text-slate-500">
                                {count}
                              </td>
                              <td className="px-6 py-4">
                                <div className="font-mono text-sm text-gray-900 dark:text-slate-100 truncate max-w-xs" title={doc.document_name}>
                                  {doc.document_name}
                                </div>
                              </td>
                              <td className="px-6 py-4 text-center flex flex-col items-center space-y-1 opacity-75">
                                <span className="bg-blue-100 dark:bg-blue-900/50 text-blue-800 dark:text-blue-200 px-2 py-1 rounded-full text-xs font-semibold">
                                  {doc.contract_number || 'N/A'}
                                </span>
                              </td>
                              <td className="px-6 py-4 text-center opacity-75">
                                <span className="text-xs font-semibold text-gray-600 dark:text-slate-400">
                                  {doc.contract_type || 'N/A'}
                                </span>
                              </td>
                              <td className="px-6 py-4 text-sm text-gray-600 dark:text-slate-400 text-center">{formatFileSize(doc.file_size)}</td>
                              <td className="px-6 py-4 text-sm text-gray-600 dark:text-slate-400 text-center">{formatDate(doc.uploaded_at)}</td>
                              <td className="px-6 py-4 text-center">
                                <span className="inline-flex items-center px-2.5 py-1 rounded-full text-xs bg-gray-100 dark:bg-slate-700 text-gray-700 dark:text-slate-300 capitalize">
                                  {doc.file_type_label?.includes("Image") 
                                    ? (<Icon name="imageFileFilled" className="w-3 h-3 mr-1 text-purple-500" />) 
                                    : doc.file_type_label?.includes("PDF")
                                      ? (<Icon name="fileFilled" className="w-3 h-3 mr-1 text-red-500" />)
                                      : doc.file_type_label?.includes("Word")
                                        ? (<Icon name="fileFilled" className="w-3 h-3 mr-1 text-blue-500" />)
                                        : (<Icon name="fileFilled" className="w-3 h-3 mr-1 text-orange-500" />)
                                  }
                                  {doc.file_type_label}
                                </span>
                              </td>
                              <td className="px-6 py-4 text-center text-sm font-medium space-x-2">
                                {isViewable(doc) ? (
                                  <button
                                  onClick={() => openDocumentViewerModal(doc)}
                                  className="text-indigo-600 dark:text-purple-400 hover:text-purple-900 dark:hover:text-purple-300 p-2 rounded-xl hover:bg-purple-100 dark:hover:bg-purple-900/30 transition-colors"
                                  title={isViewable(doc) ? 'View' : 'Download'}
                                >
                                  <Icon name="view" className="w-4 h-4" />
                                </button>
                                ) : ( <></>)}
                                
                                <button
                                  onClick={() => handleDownloadDocument(doc)}
                                  className="text-blue-600 dark:text-blue-400 hover:text-blue-900 dark:hover:text-blue-300 p-2 rounded-xl hover:bg-blue-100 dark:hover:bg-blue-900/30 transition-colors"
                                  title="Download"
                                >
                                  <Icon name="download" className="w-4 h-4" />
                                </button>
                                <button
                                  onClick={() => handleDeleteDocument(doc)}
                                  className="text-red-600 dark:text-red-400 hover:text-red-900 dark:hover:text-red-300 p-2 rounded-xl hover:bg-red-100 dark:hover:bg-red-900/30 transition-colors"
                                  title="Delete"
                                >
                                  <Icon name="delete" className="w-4 h-4" />
                                </button>
                              </td>
                            </tr>
                          );
                        })}
                      </React.Fragment>
                    ));
                  })()}
                  {/* Load More / Nothing Follows row */}
                  <tr className="bg-gray-50 dark:bg-slate-700/30">
                    <td colSpan="8" className="px-6 py-4 text-center">
                      {loadingMore ? (
                        <div className="flex items-center justify-center space-x-2">
                          <svg className="animate-spin h-4 w-4 text-indigo-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                          </svg>
                          <span className="text-sm text-gray-600 dark:text-slate-400">Loading more...</span>
                        </div>
                      ) : hasMore ? (
                        <button
                          onClick={handleLoadMore}
                          className="text-sm font-semibold text-indigo-600 hover:text-indigo-800 dark:text-indigo-400 dark:hover:text-indigo-200 py-2 px-6 rounded-xl hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-colors cursor-pointer"
                        >
                          Load More
                        </button>
                      ) : (
                        <span className="text-sm text-gray-400 dark:text-slate-500 italic">
                          — Nothing Follows —
                        </span>
                      )}
                    </td>
                  </tr>
                </>
              )}
            </tbody>
          </table>
        </div>



    </div>
  </div>
  );
};

export default Documents;
