import React, { useEffect, useState } from 'react';
import { useContractModal, useDeletedContractsModal, Counter } from '../services/api';
import Analytics, { BarChart, LineChart } from './Analytics';
import { Icon } from '../components/icons';
import LayeredImage from '../components/LayeredImage';
import bgImage from '../img/pots4.png';

const Dashboard = ({ onNavigate }) => {

  const { openContractModal } = useContractModal();
  const { openDeletedContractsModal } = useDeletedContractsModal();
  const [message, setMessage] = useState('Loading...');
  const [total_contracts, setTotalContracts] = useState(0);
  const [active_contracts, setActiveContracts] = useState(0);
  const [completed_contracts, setCompletedContracts] = useState(0);
  const [inactive_contracts, setInactiveContracts] = useState(0);
  const [near_expiry_contracts, setNearExpiryContracts] = useState(0);
  const [expired_contracts, setExpiredContracts] = useState(0);
  const [deleted_contracts, setDeletedContracts] = useState(0);
  const [pots, setPots] = useState([]);
  const [currentPot, setCurrentPot] = useState(1);

  
  // Temporary sample pots for UI testing (10 items)
  useEffect(() => {
    const samplePots = Array.from({ length: 10 }).map((_, idx) => {
      const id = idx + 1;
      return {
        id,
        price: 10_000 + id * 250,
        description: `Sample pot #${id} for UI testing`,
        qty: 5 + (id % 6),
        // PotViewer only needs `image` plus positioning; x/y are used by <Pot />.
        image: bgImage,
        x: `${idx * 120}px`,
        y: `0px`,
      };
    });

    setPots(samplePots);
  }, []);


  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const potQuery = params.get('pot');
    if (potQuery) {
      setCurrentPot(parseInt(potQuery, 10));
    }
  }, []);

  const HOST = window.location.hostname; 
  const API_BASE_URL = `http://${HOST}/legal`;
  const MEDIA_BASE_URL = `http://${HOST}`;
  
  useEffect(() => {
    fetch(`${API_BASE_URL}/dashboard/`)
      .then(res => res.json())
      .then(data => {
        setMessage(data.message);
        setInactiveContracts(data.inactive_contracts);
        setTotalContracts(data.total_contracts);
        setActiveContracts(data.active_contracts);
        setCompletedContracts(data.completed_contracts);
        setNearExpiryContracts(data.near_expiry_contracts);
        setExpiredContracts(data.expired_contracts);
        setDeletedContracts(data.deleted_contracts);
      })
      .catch(err => setMessage('Error: ' + err.message));
  }, []);

  return (
    <div className="flex">      
      <div className="flex-1 lg:ml-0 transition-all duration-30 rounded-xl">
        <div className="p-25">
          <div className="w-full mx-auto">
            <div className="w-full backdrop-blur-xl bg-transparent rounded-3xl shadow-2xl p-5 border border-white/50"
            >
              <LayeredImage />

              <div className=" mb-8 w-full text-center">
                  {/* <span className="text-3xl font-bold bg-gradient-to-r from-amber-300 via-orange-400 to-rose-500 bg-clip-text text-transparent"> */}
                <span className="w-full text-3xl font-bold text-white uppercase align-center">
                  the populars
                </span>

              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 mb-12"
                    
              >
                

              </div>
              <div className="text-center">
                <button 
                  // onClick={() => openContractModal(() => {})}
                  className="inline-flex bg-gradient-to-r from-emerald-500 to-teal-500 hover:from-emerald-600 hover:to-teal-600 text-white font-bold py-5 px-16 rounded-3xl shadow-2xl transform hover:scale-105 hover:shadow-3xl transition-all duration-300 text-xl"
                >
                  Browse Catalog

                </button>
              </div>



            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
