import React, { useState } from 'react';
import Modal from './Modal';
import { changePassword } from '../../services/api';

function getCookie(name) {
  let cookieValue = null;
  if (document.cookie && document.cookie !== '') {
    const cookies = document.cookie.split(';');
    for (let i = 0; i < cookies.length; i++) {
      const cookie = cookies[i].trim();
      if (cookie.substring(0, name.length + 1) === (name + '=')) {
        cookieValue = decodeURIComponent(cookie.substring(name.length + 1));
        break;
      }
    }
  }
  return cookieValue;
}

const ChangePasswordModal = ({ isOpen, onClose }) => {
  const [form, setForm] = useState({ username: '', old_password: '', new_password: '', renew_password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const curr_url = window.location.pathname;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (form.new_password !== form.renew_password) {
      setError('New password and confirmation do not match.');
      return;
    }

    if (!form.username || !form.old_password || !form.new_password) {
      setError('Please complete all required fields.');
      return;
    }

    const csrfToken = getCookie('csrftoken');
    
    setLoading(true);
    try {
      await changePassword({
        username: form.username,
        old_password: form.old_password,
        new_password: form.new_password,
        renew_password: form.renew_password,
      }, {
        headers: {
          'X-CSRFToken': csrfToken,
        },
      });
      setSuccess('Password changed successfully');
      setTimeout(() => {
        setSuccess('');
        onClose();
      }, 900);
    } catch (err) {
      console.error(err);
      setError('Failed to change password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Change Password"
      size="3xl"
      theme="emerald"
      footer={(
        <div className="flex space-x-3 pt-4">
          <button onClick={onClose} className="flex-1 bg-gray-100 hover:bg-gray-200 text-gray-900 font-medium py-3 px-6 rounded-2xl">Cancel</button>
          <button onClick={handleSubmit} disabled={loading} className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-white font-semibold py-3 px-6 rounded-2xl disabled:opacity-50">
            {loading ? 'Submitting…' : 'Change Password'}
          </button>
        </div>
      )}
    >
      {error && <div className="mb-4 text-sm text-red-600">{error}</div>}
      {success && <div className="mb-4 text-sm text-emerald-600">{success}</div>}
      <form className="space-y-4 grid grid-cols-2 gap-x-4 dark:text-white" onSubmit={handleSubmit}>
        <input type="hidden" value={curr_url}/>
        <div className="mt-[16px]">
          <label className="block text-sm font-semibold text-gray-700 mb-2 dark:text-slate-300">Username</label>
          <input name="username" value={form.username} onChange={handleChange} className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all" placeholder="Username" />
        </div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-2 dark:text-slate-300">Current Password</label>
          <input name="old_password" type="password" value={form.old_password} onChange={handleChange} className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all" placeholder="Current password" />
        </div>
        <div className="col-span-2 h-[5px] bg-gray-200 rounded-lg"></div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-2 dark:text-slate-300">New Password</label>
          <input name="new_password" type="password" value={form.new_password} onChange={handleChange} className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all" placeholder="New password" />
        </div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-2 dark:text-slate-300">Confirm New Password</label>
          <input name="renew_password" type="password" value={form.renew_password} onChange={handleChange} className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all" placeholder="Confirm new password" />
        </div>
      </form>
    </Modal>
  );
};

export default ChangePasswordModal;
