import React, { useRef } from 'react';
import { motion, useScroll, useTransform } from 'framer-motion';

function ScrollFadeImage() {
  const containerRef = useRef(null);

  // Tracks the scroll progress of this specific section
  // ["start end" = when top of image enters bottom of screen]
  // ["end start" = when bottom of image leaves top of screen]
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end start"]
  });

  // Maps scroll progress (0 to 1) to opacity values (1 down to 0)
  const opacity = useTransform(scrollYProgress, [0, 0.8], [1, 0]);
  
  // Optional: Add a slight zoom-out scale effect along with the fade
  // const scale = useTransform(scrollYProgress, [0, 1], [1, 0.95]);

  return (
    <div ref={containerRef} className="relative h-screen w-full overflow-hidden">
      {/* Framer Motion wrapper combined with Tailwind utilities */}
      <motion.div 
        style={{ opacity }}
        className="absolute inset-0 h-full w-full"
        
      >
        {/* Dark overlay mask to keep text legible */}
        <div className="absolute inset-0" />
      </motion.div>

      {/* Floating Content Over the Image */}
      <div className="relative z-10 flex h-full flex-col items-center justify-center text-center text-white p-4">
        <h1 className="text-5xl font-bold tracking-wide drop-shadow-[0px_0px_5px_rgba(0,0,0,0.85)]  ">EMALEXPOTS.ph</h1>
        <p className="mt-4 text-xl font-semibold italic drop-shadow-[0px_0px_5px_rgba(0,0,0,0.85)]">Business Tagline / motivational quote</p>
      </div>
    </div>
  );
}

export default ScrollFadeImage;