import React from 'react';

// Base SVG wrapper — handles common props
export const SvgIcon = ({ children, className = 'w-5 h-5', ...props }) => (
  <svg
    className={className}
    fill="none"
    stroke="currentColor"
    viewBox="0 0 24 24"
    xmlns="http://www.w3.org/2000/svg"
    {...props}
  >
    {children}
  </svg>
);

// Base SVG wrapper for FILLED icons
export const SvgFilled = ({ children, className = 'w-5 h-5', ...props }) => (
  <svg
    className={className}
    fill="currentColor"
    viewBox="0 0 24 24"
    xmlns="http://www.w3.org/2000/svg"
    {...props}
  >
    {children}
  </svg>
);

