
import React, { useRef, useEffect, useMemo, useState } from 'react';
import { Bar, Line } from 'react-chartjs-2';
import zoomPlugin from 'chartjs-plugin-zoom';
import 'chartjs-adapter-date-fns';
import { Chart as ChartJS, Filler, CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend, PointElement, LineElement, TimeScale  } from 'chart.js';


// Chart.js registration is already done globally in src/index.js,
// but keeping this import ensures the file is self-contained if needed.
ChartJS.register(CategoryScale, LinearScale, BarElement, PointElement, LineElement, Title, Tooltip, Legend, zoomPlugin, TimeScale, Filler);

const buildYearlyEffectiveCountsByType = (contracts) => {
  // Bar chart requirement:
  // - X-axis: effectivity year
  // - Y-axis: count of contracts effective in that year
  // - Different bars per contract type

  // We treat `start_date` as effectivity date.
  // Contract type is expected as `contract_type` (string or object) from backend serializer.
  const countsByYearAndType = {}; // { [year]: { [typeName]: count } }
  const typeSet = new Set();

  (contracts || []).forEach((c) => {
    const d = c?.start_date || c?.effectivity_date || c?.effective_date;
    if (!d) return;

    const year = new Date(d).getFullYear();
    if (Number.isNaN(year)) return;

    // contract_type may be a string (from serializer) or an object
    const typeName =
      (typeof c?.contract_type === 'string' && c.contract_type) ||
      c?.contract_type?.name ||
      'Unknown';

    typeSet.add(typeName);

    countsByYearAndType[year] = countsByYearAndType[year] || {};
    countsByYearAndType[year][typeName] =
      (countsByYearAndType[year][typeName] || 0) + 1;
  });

  const labels = Object.keys(countsByYearAndType)
    .sort((a, b) => Number(a) - Number(b))
    .map(String);

  const types = Array.from(typeSet);

  return { labels, types, countsByYearAndType };
};

function generateDailyContractTimeline(contracts, type) {
  const dailyCounts = {};
  
  contracts.forEach(contract => {
    let current = new Date(contract.start_date);
    let yesterdaysDate = new Date(current);
    yesterdaysDate.setDate(yesterdaysDate.getDate() - 1);
    const end = new Date(contract.end_date);
    const contractTypeName =
      (typeof contract?.contract_type === 'string' && contract.contract_type) ||
      contract?.contract_type?.name ||
      'Unknown';
    
    // Loop through every day from start to end date of this specific contract
    if (contractTypeName === type) {
      const yesterdaysDateString = yesterdaysDate.toISOString();
      dailyCounts[yesterdaysDateString] = (dailyCounts[yesterdaysDateString] || null);
      while (current <= end) {
        const dateString = current.toISOString(); // Format: YYYY-MM-DD
        
        // Increment the count of active contracts for this specific calendar day
        dailyCounts[dateString] = (dailyCounts[dateString] || 0) + 1;
        
        // Move to the next calendar day
        current.setDate(current.getDate() + 1);
      }
    }

  });

  // 3. Map the object into Chart.js coordinate objects sorted chronologically
  return Object.keys(dailyCounts)
    .sort()
    .map(date => ({ x: date, y: dailyCounts[date] }));
}

const buildMonthlyEffectiveCountsByType = (contracts, monthsSpan = 12) => {
  // Active rule (inclusive): start_date <= month_end AND end_date >= month_start
  const parseDate = (v) => {
    if (!v) return null;
    const d = new Date(v);
    if (Number.isNaN(d.getTime())) return null;
    return d;
  };

  const getStartDate = (c) => c?.start_date || c?.effectivity_date || c?.effective_date;
  const getEndDate = (c) => c?.end_date || c?.endDate;

  const monthKey = (dateObj) => {
    const y = dateObj.getFullYear();
    const m = dateObj.getMonth();
    return `${y}-${String(m + 1).padStart(2, '0')}`; // YYYY-MM
  };

  const monthLabel = (key) => {
    const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const [y, mm] = key.split('-');
    const mIndex = Number(mm) - 1;
    return `${MONTHS[mIndex]} ${y}`;
  };

  const addMonths = (dateObj, delta) => {
    const d = new Date(dateObj);
    d.setMonth(d.getMonth() + delta);
    return d;
  };

  const contractRows = (contracts || [])
    .map((c) => {
      const typeName =
        (typeof c?.contract_type === 'string' && c.contract_type) ||
        c?.contract_type?.name ||
        'Unknown';

      const startDt = parseDate(getStartDate(c));
      const endDt = parseDate(getEndDate(c));


      if (!startDt || !endDt) return null;
      if (endDt < startDt) return null;
      return { typeName, startDt, endDt };
    })
    .filter(Boolean);

  if (!contractRows.length) {
    return { labels: [], types: [], countsByMonthAndType: {} };
  }

  const maxStart = contractRows.reduce((max, x) => (x.startDt > max ? x.startDt : max), contractRows[0].startDt);
  const windowEnd = new Date(maxStart.getFullYear(), maxStart.getMonth(), 1);
  const windowStart = addMonths(windowEnd, -(monthsSpan - 1));

  const monthKeys = [];
  let cursor = new Date(windowStart);
  for (let i = 0; i < monthsSpan; i++) {
    monthKeys.push(monthKey(cursor));
    cursor = addMonths(cursor, 1);
  }

  const typeSet = new Set();
  const countsByMonthAndType = {};

  monthKeys.forEach((mk) => {
    const [y, mm] = mk.split('-');
    const monthStart = new Date(Number(y), Number(mm) - 1, 1);
    const monthEnd = new Date(Number(y), Number(mm), 0, 23, 59, 59, 999); // inclusive end of month (with time) 


    contractRows.forEach(({ typeName, startDt, endDt }) => {
      const active = startDt <= monthEnd && endDt >= monthStart;
      if (!active) return;

      typeSet.add(typeName);
      var mkLabel = monthLabel(mk);
      countsByMonthAndType[mkLabel] = countsByMonthAndType[mkLabel] || {};
      countsByMonthAndType[mkLabel][typeName] = (countsByMonthAndType[mkLabel][typeName] || 0) + 1;
    });
  });

  const types = Array.from(typeSet);
  const labels = monthKeys.map(monthLabel);
  // Ensure we always return non-empty datasets if there is any date data.
  // (Helps avoid chart showing all zeros due to unexpected date parsing/timezone issues.)

  return { labels, types, countsByMonthAndType };
}


const makeColorPalette = (n) => {
  // simple deterministic palette
  const base = [
    'rgba(59, 130, 246, 0.6)', // blue
    'rgba(16, 185, 129, 0.6)', // emerald
    'rgba(245, 158, 11, 0.6)', // amber
    'rgba(239, 68, 68, 0.6)', // red
    'rgba(168, 85, 247, 0.6)', // purple
    'rgba(99, 102, 241, 0.6)', // indigo
    'rgba(20, 184, 166, 0.6)', // teal
    'rgba(236, 72, 153, 0.6)', // pink
  ];

  const colors = [];
  for (let i = 0; i < n; i++) {
    colors.push(base[i % base.length]);
  }
  return colors;
};


