export const LineChart = ({isChartOnly=false}) => {
  const chartRef = useRef(null)
  const HOST = window.location.hostname;
  const API_BASE_URL = `http://${HOST}/legal`;


  const [loading, setLoading] = useState(true);
  const [contracts, setContracts] = useState([]);
  const [error, setError] = useState('');

  useEffect(() => {
    const run = async () => {
      if (chartRef.current) {
        chartRef.current.destroy();
      }
      
      try {
        setLoading(true);
        setError('');

        // Fetch all contracts (you can add pagination in the backend if needed)
        const res = await fetch(`${API_BASE_URL}/contracts/?limit=10000&offset=0`);
        if (!res.ok) throw new Error('Failed to fetch contracts');

        const json = await res.json();
        const results = Array.isArray(json) ? json : json?.results || [];
        setContracts(results);
      } catch (e) {
        setError(e.message || String(e));
      } finally {
        setLoading(false);
      }
    };

    run();
  }, []);

  const lineChartData = useMemo(() => {
    const { labels, types, countsByMonthAndType } = buildMonthlyEffectiveCountsByType(contracts);

    const colors = makeColorPalette(types.length);
    return {
      labels,
      datasets: types.map((typeName, idx) => {
        // const data = labels.map((month) => countsByMonthAndType?.[month]?.[typeName] || 0);
        return {
          fill: true,
          label: typeName,
          data: generateDailyContractTimeline(contracts, typeName),
          borderColor: colors[idx].replace('0.6', '1'),
          // backgroundColor: colors[idx],
          // tension: 0.35,
          backgroundColor: (context) => {
            const color = colors[idx];
            const chart = context.chart;
            const { ctx, chartArea } = chart;

            if (!chartArea) {
              // This ensures a fallback color while the chart is initially initializing
              return 'rgba(75, 192, 192, 0.2)';
            }

            // Create a vertical gradient matching the height of your chart canvas
            const gradient = ctx.createLinearGradient(0, chartArea.top, 0, chartArea.bottom);
            gradient.addColorStop(0, color.replace('0.6', '0.6')); // Vibrant color at the top line
            gradient.addColorStop(1, color.replace('0.6', '0.0')); // Fully transparent at the bottom

            return gradient;
          },
          borderWidth: 2,
          // tension: 0.25,
          pointRadius: 3,
          pointHoverRadius: 5,

        };
      }),
    };
  }, [contracts]);

  const VIEW_WINDOW = 7 * 24 * 60 * 60 * 1000; // 7 days at a time
  const ONE_DAY_MS = 24 * 60 * 60 * 1000; 
  const ONE_YEAR_MS = 2 * 365 * 24 * 60 * 60 * 1000;

  const [sliderVal, setSliderVal] = useState(0);

  const derivedPanBounds = useMemo(() => {
    const dates = (contracts || [])
      .map((c) => c?.start_date || c?.effectivity_date || c?.effective_date)
      .filter(Boolean)
      .map((d) => new Date(d).getTime())
      .filter((t) => Number.isFinite(t));

    const endDates = (contracts || [])
      .map((c) => c?.end_date || c?.endDate)
      .filter(Boolean)
      .map((d) => new Date(d).getTime())
      .filter((t) => Number.isFinite(t));

    // If data has no valid dates, fall back to a safe window (avoids crashing).
    const minT = dates.length ? Math.min(...dates) : new Date().getTime();
    const maxT = endDates.length ? Math.max(...endDates) : minT + VIEW_WINDOW;

    // Ensure we don't end up with a negative range.
    const totalPanRange = Math.max((maxT - VIEW_WINDOW) - minT, 0);

    return { START_DATE: minT, END_DATE: maxT, TOTAL_PAN_RANGE: totalPanRange };
  }, [contracts]);

  const chartOptions = useMemo(() => {
    const { START_DATE, END_DATE, TOTAL_PAN_RANGE } = derivedPanBounds;

    // Prevent slider/pan from being “stuck” due to missing chart instance refs.
    // (react-chartjs-2 only provides chartRef via ref forwarding on the Line component)
    const shouldEnablePan = Number.isFinite(START_DATE) && Number.isFinite(END_DATE) && TOTAL_PAN_RANGE > 0;

    const initialMin = START_DATE - ((END_DATE-START_DATE)/10);
    const initialMax = END_DATE + ((END_DATE-START_DATE)/10);

    return {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: true },
        tooltip: { enabled: true },
        zoom: {
          pan: {
            enabled: true,
            mode: 'x',
            onPan: ({ chart }) => {
              const currentMin = chart.scales.x.min;
              const currentMax = chart.scales.x.max;
              const visibleRange = currentMax - currentMin;
              const percentage = TOTAL_PAN_RANGE
                ? ((currentMin - START_DATE) / TOTAL_PAN_RANGE) * 100
                : 0;
              setSliderVal(Math.min(Math.max(percentage, 0), 100));

              // Clamp the visible window to the overall data bounds
              let newMin = currentMin;
              let newMax = currentMax;

              if (newMin < (START_DATE-(visibleRange/10))) {
                newMin = (START_DATE-(visibleRange/10));
                newMax = newMin + visibleRange;
              }

              if (newMax > (END_DATE+(visibleRange/10))) {
                newMax = (END_DATE+(visibleRange/10));
                newMin = newMax - visibleRange;
              }

              // Ensure final values are within bounds even if visibleRange > total span
              if (newMin < (START_DATE-(visibleRange/10))) newMin = (START_DATE-(visibleRange/10));
              if (newMax > (END_DATE+(visibleRange/10))) newMax = (END_DATE+(visibleRange/10));

              if (newMin !== currentMin || newMax !== currentMax) {
                chart.options.scales.x.min = newMin;
                chart.options.scales.x.max = newMax;
                chart.update('none');
              }
            },
          },
          zoom: {
            wheel: { enabled: true },
            pinch: { enabled: true },
            mode: 'x',
            limits: {
              x: { min: START_DATE, max: END_DATE, minRange: ONE_DAY_MS, maxRange: END_DATE - START_DATE},
            },
            onZoom: ({ chart }) => {
              const currentMin = chart.scales.x.min;
              const currentMax = chart.scales.x.max;
              const currentRange = currentMax - currentMin;
              // If user attempts to zoom closer than 1 day, force it back to 1 day
              if (currentRange < (ONE_DAY_MS * 12)) {
                const centerPoint = currentMin + (currentRange / 2);
                chart.options.scales.x.min = centerPoint - (((ONE_DAY_MS * 12)) / 2);
                chart.options.scales.x.max = centerPoint + (((ONE_DAY_MS * 12)) / 2);
                chart.update('none'); // Update scale smoothly without layout flickering
              }

              if (currentRange > ONE_YEAR_MS) {
                const centerPoint = currentMin + (currentRange / 2);
                chart.options.scales.x.min = centerPoint - (ONE_YEAR_MS / 2);
                chart.options.scales.x.max = centerPoint + (ONE_YEAR_MS / 2);
                chart.update('none');
              }

              // Always ensure zoom does not exceed overall data bounds
              if (chart.options.scales.x.min < START_DATE) chart.options.scales.x.min = START_DATE;
              if (chart.options.scales.x.max > END_DATE) chart.options.scales.x.max = END_DATE;
              chart.update('none');
            }
          },
        },
      },
      scales: {
        x: {
          type: 'time',
          time: {
            tooltipFormat: 'MMM d, yyyy',
            displayFormats: {
              hour: 'MMM d',
              day: 'MMM d',
              month: 'MMM yyyy',
              year: 'yyyy',
            },
          },
          min: initialMin,
          max: initialMax,
          ticks: {
            maxTicksLimit: 10, 
            minTicksLimit: 5,
            autoSkip: true
          }
        },
        y: {
          beginAtZero: true,
          ticks: {
            precision: 0,
            callback: function(value, index, ticks) {
              return value + ' contracts'; 
            }
          },
          afterBuildTicks: (axis) => {
            if (!axis.ticks || axis.ticks.length < 2) return;

            const lastTickVal = axis.ticks[axis.ticks.length - 1].value;
            const secondLastTickVal = axis.ticks[axis.ticks.length - 2].value;

            const nativeTickStep = lastTickVal - secondLastTickVal;

            const extraTick1 = lastTickVal + nativeTickStep;

            axis.ticks.push(
              { value: extraTick1, label: String(extraTick1) }
            );

            axis.max = extraTick1;
          }
        },
      },
    };
  }, [derivedPanBounds]);

  const handleScroll = (e) => {
    const val = parseFloat(e.target.value);
    setSliderVal(val);

    const { START_DATE, TOTAL_PAN_RANGE } = derivedPanBounds;
    const chartInstance = chartRef.current;
    if (!chartInstance || !Number.isFinite(START_DATE)) return;

    // Map 0..100 -> [START_DATE .. END_DATE - VIEW_WINDOW]
    const percentage = val / 100;
    const newMin = START_DATE + TOTAL_PAN_RANGE * percentage;
    const newMax = newMin + VIEW_WINDOW;

    // Directly mutate scale configs for lag-free rendering
    chartInstance.options.scales.x.min = newMin;
    chartInstance.options.scales.x.max = newMax;
    chartInstance.update('none');
  };

  if(isChartOnly){
    return (<div className="h-[420px] w-full">
      {loading ? (
        <div className="text-gray-600 dark:text-slate-300">Loading...</div>
      ) : error ? (
        <div className="text-red-600 dark:text-red-400">{error}</div>
      ) : (
        <Line ref={chartRef} data={lineChartData} options={chartOptions} />
      )}
    </div>);
  }

  return (
    <div className="flex">
      <div className="flex-1 lg:ml-0 transition-all duration-30 rounded-xl">
        <div className="p-6">
          <div className="max-w-6xl mx-auto">
            <div className="bg-white/80 dark:bg-slate-800/80 backdrop-blur-xl rounded-3xl shadow-2xl p-12 border border-white/50">
              <div className="mb-8">
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Monthly effective contracts</h2>
                <p className="text-gray-600 dark:text-slate-300 mt-2">
                  Line chart of active contracts per month (by contract type)'
                </p>
              </div>

              {loading ? (
                <div className="text-gray-600 dark:text-slate-300">Loading...</div>
              ) : error ? (
                <div className="text-red-600 dark:text-red-400">{error}</div>
              ) : (
                <div className="h-[420px] w-full">
                  <Line ref={chartRef} data={lineChartData} options={chartOptions} />
                </div>
              )}
              <div className="mb-[10px]">
                <input className="w-full cursor-pointer"
                  type="range"
                  min="0"
                  max="100"
                  step="0.1"
                  value={sliderVal}
                  onChange={handleScroll}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

}

