import React from 'react';
import { Icon } from './icons';
import { useTheme } from '../context/ThemeContext';

const Header = ({ sidebarOpen, setSidebarOpen, title, subTitle, cart, setCart }) => {
  const { currentTheme, toggleTheme } = useTheme();

  const themes = ['light', 'dark', 'system'];
  const currentIndex = themes.indexOf(currentTheme);
  const nextIndex = (currentIndex + 1) % themes.length;
  const nextTheme = themes[nextIndex];

  const themeIconNames = {
    'light': 'day',
    'dark': 'night',
    'system': 'system'
  };
  const getIconName = (theme) => {
    return themeIconNames[theme] || 'day';
  };

  return (
    <header className="dark:bg-gradient-to-r dark:text-white backdrop-blur-xl w-full shadow-sm absolute fixed top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center py-4">
          <div className="flex items-center space-x-3">
            <div>
              <button 
                onClick={() => setSidebarOpen(!sidebarOpen)}
                className="lg:hidden p-1 mr-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg transition-all duration-200"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                </svg>
              </button>
              <span className="text-xl md:text-2xl font-black bg-gradient-to-r from-gray-900 dark:from-slate-100 to-gray-700 dark:to-slate-300 bg-clip-text">
                {title || 'Dashboard'}
              </span>
              <div>
                {subTitle && (
                  <p className="text-sm text-gray-600 dark:text-gray-400">
                    {subTitle}
                  </p>
                ) || ''}
              </div>
            </div>
          </div>

          <div className="flex items-center space-x-3">
            <button
              onClick={toggleTheme}
              className="shadow-lg dark:shadow-white p-2.5 bg-gray-100/80 dark:bg-gray-100/10 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-xl transition-all duration-200 text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white shadow-sm"
              title={`Switch to ${nextTheme} mode`}
            >
              <Icon name="user" className="w-5 h-5" />
            </button> 
            <button
              onClick={toggleTheme}
              className="shadow-lg dark:shadow-white p-2.5 bg-gray-100/80 dark:bg-gray-100/10 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-xl transition-all duration-200 text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white shadow-sm"
              title={`Switch to ${nextTheme} mode`}
            >
              <Icon name="shoppingCart" className="w-5 h-5" />
            </button> 
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;
