import React, { createContext, useContext, useState, useCallback } from 'react';
import { ContractModal, DocumentViewerModal, ChangePasswordModal, DeletedContractsModal } from '../components/modals/Modals';

const ModalContext = createContext();

export const ModalProvider = ({ children }) => {
  const [modalState, setModalState] = useState({
    type: null,
    isOpen: false,
    onSubmit: null,
    props: {},
  });

  const openModal = useCallback((type, onSubmit, props = {}) => {
    setModalState({ type, isOpen: true, onSubmit, props });
  }, []);

  const closeModal = useCallback(() => {
    setModalState({ type: null, isOpen: false, onSubmit: null, props: {} });
  }, []);

  const handleSubmit = (data, files, docType) => {
    if (modalState.onSubmit) {
      modalState.onSubmit(data, files, docType);
    }
  };

  return (
    <ModalContext.Provider value={{ openModal, closeModal }}>
      {children}
      {modalState.type === 'contract' && (
        <ContractModal
          isOpen={modalState.isOpen}
          onClose={closeModal}
          onSubmit={handleSubmit}
          {...modalState.props}
        />
      )}
      {modalState.type === 'documentViewer' && (
        <DocumentViewerModal
          isOpen={modalState.isOpen}
          onClose={closeModal}
          document={modalState.props.document}
        />
      )}
      {modalState.type === 'deletedContracts' && (
        <DeletedContractsModal
          isOpen={modalState.isOpen}
          onClose={closeModal}
          {...modalState.props}
        />
      )}
      {modalState.type === 'change_password' && (
        <ChangePasswordModal
          isOpen={modalState.isOpen}
          onClose={closeModal}
        />
      )}
    </ModalContext.Provider>
  );
};

export const useModal = (modalId) => {
  const context = useContext(ModalContext);
  if (!context) {
    throw new Error('useModal must be used within ModalProvider');
  }
  return context;
};