import React, { useEffect, useState } from 'react';
import { fetchAuditLogs } from '../services/api';
import { useContractModal, 
         fetchContracts, 
         useDocumentViewModal, 
         getDocument } from '../services/api';

// import { Icon } from '../components/icons';

const Recents = () => {
  // const { openContractModal, openViewContractModal, openEditContractModal } = useContractModal();
  const { openViewContractModal } = useContractModal();
  const { openDocumentViewerModal,  } = useDocumentViewModal();

  const [logs, setLogs] = useState([]);
  const [offset, setOffset] = useState(0);
  const [hasMore, setHasMore] = useState(false);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [appliedSearch, setAppliedSearch] = useState('');
  const [appliedStartDate, setAppliedStartDate] = useState('');
  const [appliedEndDate, setAppliedEndDate] = useState('');

  const normalizeLogsResponse = (data) => {
    if (Array.isArray(data)) {
      return { results: data, has_more: data.length === 50 };
    }
    return data;
  };

  const formatDateTime = (value) => {
    if (!value) return '';
    const date = new Date(value);
    const day = String(date.getDate()).padStart(2, '0');
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const year = date.getFullYear();
    let hours = date.getHours();
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const ampm = hours >= 12 ? 'PM' : 'AM';
    hours = hours % 12 || 12;
    return `${day}/${month}/${year} ${String(hours).padStart(2, '0')}:${minutes} ${ampm}`;
  };

  const loadLogs = async (nextOffset = 0, append = false, filterValues = {}) => {
    if (nextOffset > 0) {
      setLoadingMore(true);
    } else {
      setLoading(true);
      setError('');
    }

    try {
      const params = { limit: 50, offset: nextOffset };
      const searchValue = filterValues.search !== undefined ? filterValues.search : appliedSearch;
      const startValue = filterValues.start_date !== undefined ? filterValues.start_date : appliedStartDate;
      const endValue = filterValues.end_date !== undefined ? filterValues.end_date : appliedEndDate;

      if (searchValue) params.search = searchValue;
      if (startValue) params.start_date = startValue;
      if (endValue) params.end_date = endValue;

      const response = await fetchAuditLogs(params);
      const data = normalizeLogsResponse(response);

      setLogs((prevLogs) => (append ? [...prevLogs, ...data.results] : data.results));
      setOffset(nextOffset);
      setHasMore(Boolean(data.has_more));
    } catch (err) {
      console.error('Failed to load audit logs:', err);
      setError(err.message || 'Failed to load audit logs');
    } finally {
      if (nextOffset > 0) {
        setLoadingMore(false);
      } else {
        setLoading(false);
      }
    }
  };

  const normalizeDatetime = (dateValue) => {
    if (!dateValue) return '';
    // If value is just a date (YYYY-MM-DD), append T00:00:00.000Z
    if (dateValue.length === 50) {
      return `${dateValue}T00:00:00.000Z`;
    }
    // For full datetime (YYYY-MM-DDTHH:MM), convert local time to UTC ISO string
    try {
      const date = new Date(dateValue);
      return date.toISOString();
    } catch {
      return dateValue;
    }
  };

  const handleApplyFilter = () => {
    const nextAppliedSearch = search;
    const nextAppliedStartDate = normalizeDatetime(startDate);
    const nextAppliedEndDate = normalizeDatetime(endDate);

    setAppliedSearch(nextAppliedSearch);
    setAppliedStartDate(nextAppliedStartDate);
    setAppliedEndDate(nextAppliedEndDate);
    setOffset(0);
    loadLogs(0, false, {
      search: nextAppliedSearch,
      start_date: nextAppliedStartDate,
      end_date: nextAppliedEndDate,
    });
  };

  const handleClearFilter = () => {
    setSearch('');
    setStartDate('');
    setEndDate('');
    setAppliedSearch('');
    setAppliedStartDate('');
    setAppliedEndDate('');
    setOffset(0);
    loadLogs(0, false, { search: '', start_date: '', end_date: '' });
  };

  

  const handleLoadMore = () => {
    if (loadingMore || loading) return;
    if (!hasMore) return;

    const nextOffset = logs.length; // keep offset consistent with appended results
    loadLogs(nextOffset, true);
  };

  useEffect(() => {
    loadLogs(0, false);
  }, []);

  var count = 1;
  return (
    <div className="space-y-6">
      {/* <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-slate-900 dark:text-slate-100">Recent Activity</h1>
          <p className="mt-2 text-sm text-slate-500 dark:text-slate-400">Review the latest contract and document changes.</p>
        </div>
        <div className="inline-flex items-center gap-2 px-4 py-3 rounded-2xl bg-indigo-500 text-white shadow-lg">
          <Icon name="clockFilled" className="w-5 h-5" />
          <span>Latest changes</span>
        </div>
      </div> */}

      {/* <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-gray-200 dark:border-slate-700 p-6"> */}
        <div className="flex flex-col gap-1">
          <div className="flex justify-end gap-3">
            <button
              onClick={handleApplyFilter}
              className="px-6 py-2 rounded-lg bg-red-600 hover:bg-red-700 text-white font-medium transition-colors duration-200"
            >
              Apply Filter
            </button>
            <button
              onClick={handleClearFilter}
              className="px-6 py-2 rounded-lg bg-red-600 hover:bg-red-700 text-white font-medium transition-colors duration-200"
            >
              Clear Filters
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-6 gap-4 items-end">
            <div className="flex-1 col-span-4">
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                Search
              </label>
              <input
                type="text"
                placeholder="Search by entity, field, or user..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-slate-100 placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-red-500"
              />
            </div>
            <div className="flex-1">
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                Date After
              </label>
              <input
                type="datetime-local"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-red-500"
              />
            </div>
            <div className="flex-1">
              <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                Date Before
              </label>
              <input
                type="datetime-local"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-red-500"
              />
            </div>
          </div>
        </div>
      {/* </div> */}

      <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-gray-200 dark:border-slate-700 overflow-hidden">
        {loading ? 
          (
            <div className="p-8 text-center text-slate-500 dark:text-slate-400">
              Loading recent activity...
            </div>
          ) : error ? (
            <div className="p-8 text-center text-red-500">{error}</div>
          ) : logs.length === 0 ? (
            <div className="p-8 text-center text-slate-500 dark:text-slate-400">No recent activity yet.</div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-gradient-to-r from-red-500 to-red-800 text-white border-b border-gray-200 dark:border-slate-600 text-white text-sm uppercase tracking-wider">
                    <th className="text-center px-6 py-4">#</th>
                    <th className="text-center px-6 py-4">Timestamp</th>
                    <th className="text-center px-6 py-4">Entity</th>
                    <th className="text-center px-6 py-4">Action</th>
                    <th className="text-center px-6 py-4">Old Value</th>
                    <th className="text-center px-6 py-4">New Value</th>
                    <th className="text-center px-6 py-4">By</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                  {logs.map((log) => (
                    <tr key={log.id} className="text-center hover:bg-slate-50 dark:hover:bg-slate-700/80 transition-all duration-500">
                      <td className="px-6 py-4 text-sm text-slate-500 dark:text-slate-400">{count++}</td>
                      <td className="px-6 py-4 text-sm text-slate-500 dark:text-slate-400">{formatDateTime(log.created_at)}</td>
                      <td className="px-6 py-4 text-sm text-slate-700 dark:text-slate-200">
                          <span className="font-medium font-semibold">{log.entity_type}</span> -  
                          <span 
                              onClick={async () => {
                                  if(log.entity_type.toLowerCase() === 'contract') {
                                      fetchContracts({ id: log.entity_id }).then(
                                          (result) => {
                                              if (result.contract) {
                                                  openViewContractModal(result.contract);
                                              } else { 
                                                  alert('Contract not found');
                                              }
                                          },
                                          (err) => {
                                              console.error('Failed to fetch contract:', err);
                                              alert('Failed to fetch contract details');
                                          }
                                      );
                                  }
                                  else {
                                      getDocument(log.entity_id).then(
                                          (result) => {
                                              const isViewable = result?.mime_type?.startsWith('image/') || result?.mime_type === 'application/pdf';
                                              if (isViewable) {
                                                  openDocumentViewerModal(result);
                                              } else {
                                                  alert('This document type cannot be viewed in the browser. Please download it instead.');
                                              }
                                          },
                                          (err) => {
                                              console.error('Failed to fetch document:', err);
                                              alert('Failed to fetch document details');
                                          }
                                      );
                                  }
                              }}
                              className="cursor-pointer inline-flex px-3 py-1 rounded-full text-xs font-semibold bg-slate-100/80 text-black/50 dark:bg-slate-900/30 dark:text-white/50 hover:bg-slate-200 dark:hover:bg-slate-800/80 hover:text-black dark:hover:text-white transition-all duration-300">
                              #{log.entity_id}
                          </span>
                      </td>
                      <td className="px-6 py-4 text-sm text-slate-700 dark:text-slate-200">{log.field_name}</td>
                      <td className="px-6 py-4 text-sm text-slate-500 dark:text-slate-400 truncate max-w-[200px]">{log.old_value || '—'}</td>
                      <td className="px-6 py-4 text-sm text-slate-500 dark:text-slate-400 truncate max-w-[200px]">{log.new_value || '—'}</td>
                      <td className="px-6 py-4 text-sm text-slate-700 dark:text-slate-200">{log.edited_by_user?.email || 'System'}</td>
                    </tr>
                  ))}
                  {hasMore && !loading ? (
                    <tr className="p-4 border-t border-slate-200 dark:border-slate-700 text-center">
                      <td
                        colSpan="6"
                        tabIndex={0}
                        className="px-6 py-4 text-center"
                      >
                        <button
                          onClick={handleLoadMore}
                          className="text-sm font-semibold text-red-600 hover:text-red-800 dark:text-red-400 dark:hover:text-red-200 py-2 px-6 rounded-xl hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors cursor-pointer"
                        >
                          {loadingMore ? 'Loading more...' : ' Load more '}
                        </button>
                      </td>
                    </tr>
                  ) : (
                    <tr className="p-4 border-t border-slate-200 dark:border-slate-700 text-center">
                      <td colSpan="6" className="px-6 py-4 text-center">
                        <span className="text-sm text-gray-400 dark:text-slate-500 italic">
                          {loadingMore ? 'Loading more...' : ' — No more activity — '}
                        </span>
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          )
        }
      </div>
    </div>
  );
};

export default Recents;
