import React, { useEffect, useMemo, useRef, useState } from 'react';
import Modal from './Modal';
import { fetchInternalParties, fetchContractDocuments, deleteDocument, getDocumentViewUrl, getContractTypes, createContractType } from '../../services/api';


const ContractModal = ({ isOpen, onClose, onSubmit, loading = false, error = '', mode = 'create', initialData = null }) => {
  const isViewMode = mode === 'view';
  const isEditMode = mode === 'edit';
  const isCreateMode = mode === 'create';

  const [formData, setFormData] = useState({
    contract_number: '',
    contract_type: 'MOA',
    title: '',
    contractor: '',
    details: '',
    coordinator: '',
    internal_party: null,
    in_party_type: '',
    start_date: '',
    end_date: '',
    status: 'inactive',
  });
  const [files, setFiles] = useState([]);
  const [existingDocs, setExistingDocs] = useState([]);
  const [docsLoading, setDocsLoading] = useState(false);
  const [contractTypes, setContractTypes] = useState([]);
  const [showAddTypeDialog, setShowAddTypeDialog] = useState(false);
  const [newTypeForm, setNewTypeForm] = useState({ name: '', description: '' });
  const [addingType, setAddingType] = useState(false);
  const [addTypeError, setAddTypeError] = useState('');

  const [internalPartyOptions, setInternalPartyOptions] = useState([]);
  const [internalPartyLoading, setInternalPartyLoading] = useState(false);
  const internalPartyOptionsGrouped = useMemo(() => {
    const groups = {
      department: [],
      unit: [],
      section: [],
      user: [],
      custom: [],
    };

    for (const opt of internalPartyOptions) {
      const g = opt.group || 'custom';
      if (!groups[g]) groups[g] = [];
      groups[g].push(opt);
    }

    const ordered = ['department', 'unit', 'section', 'user', 'custom'];
    return ordered
      .filter((k) => groups[k])
      .map((k) => ({ key: k, options: groups[k].slice().sort((a, b) => (a.label || a.value).localeCompare(b.label || b.value)) }));
  }, [internalPartyOptions]);
  useEffect(() => {
    const loadInternalParties = async () => {
      if (!isOpen) return;
      try {
        setInternalPartyLoading(true);
        const data = await fetchInternalParties();
        const items = Array.isArray(data) ? data : data?.results ?? [];
        
        const mapped = items
          .map((item) => {
            const label = item?.name ?? item?.label ?? item?.display_name ?? item?.value ?? item?.internal_party ?? item?.custom;
            const value = item?.id ?? item?.value ?? item?.internal_party ?? item?.name ?? item?.label ?? item?.custom ?? label;
            const group = item?.group ?? item?.type ?? item?.category ?? (item?.department ? 'department' : item?.unit ? 'unit' : item?.section ? 'section' : item?.user ? 'user' : item?.custom ? 'custom' : 'custom');
            return label ? { group: normalizeGroup(group), label: String(label), value: value == null ? null : String(value) } : null;
          })
          .filter(Boolean);

        const seen = new Set();
        const unique = [];
        for (const m of mapped) {
          const key = `${m.group}|${m.value}`;
          if (seen.has(key)) continue;
          seen.add(key);
          unique.push(m);
        }

        setInternalPartyOptions(unique);
      } catch (e) {
        console.error('Failed to load internal parties:', e);
        setInternalPartyOptions([]);
      } finally {
        setInternalPartyLoading(false);
      }
    };

    loadInternalParties();
  }, [isOpen]);

  function normalizeGroup(g) {
    const s = String(g || '').toLowerCase();
    if (s.includes('depart')) return 'department';
    if (s.includes('unit')) return 'unit';
    if (s.includes('user')) return 'user';
    if (s.includes('section')) return 'section';
    return 'custom';
  }

  const CoordinatorCombobox = ({ value, onChange, onSelect }) => {

    const [query, setQuery] = useState(value || '');
    const [open, setOpen] = useState(false);
    const wrapperRef = useRef(null);

    const deferredValueRef = useRef(value || '');
    const deferTimerRef = useRef(null);


    useEffect(() => {
      setQuery(value || '');
      deferredValueRef.current = value || '';
    }, [value]);


    useEffect(() => {
      const onDocClick = (e) => {
        if (!wrapperRef.current) return;
        if (!wrapperRef.current.contains(e.target)) {
          setOpen(false);
        }
      };
      document.addEventListener('mousedown', onDocClick);
      return () => document.removeEventListener('mousedown', onDocClick);
    }, []);

    useEffect(() => {
      return () => {
        if (deferTimerRef.current) {
          clearTimeout(deferTimerRef.current);
          deferTimerRef.current = null;
        }
      };
    }, []);

    const normalizedQuery = query.trim().toLowerCase();

    const filteredByGroup = internalPartyOptionsGrouped.map((group) => {
      const opts = group.options.filter((o) => {
        if (!normalizedQuery) return true;
        const hay = `${o.label} ${o.value}`.toLowerCase();
        return hay.includes(normalizedQuery);
      });
      return { ...group, options: opts };
    });

    const anyOptions = internalPartyOptionsGrouped.some((g) => g.options.length > 0);

    return (
      <div ref={wrapperRef} className="relative">
          <input
          	type="text"
            value={query}
            onChange={(e) => {
              const next = e.target.value;
              setQuery(next);
              setOpen(true);
            }}
            onFocus={() => setOpen(true)}
            onBlur={(e) => {
                if(!e.relatedTarget?.classList?.value.includes('internal_party')){
                  setOpen(false)
                  const exist = internalPartyOptions.find(x => { return x.label.trim().toLowerCase() === query.trim().toLowerCase() })
                  if(exist){
                    setFormData((prev) => ({ ...prev, internal_party: exist.value, coordinator: exist.label.trim(), in_party_type: exist.group }))
                    onChange(exist.label.trim())
                  }
                  else {
                    onChange(query.trim())
                    setFormData((prev) => ({ ...prev, internal_party: null, coordinator: query.trim(), in_party_type: 'custom' }))
                  }
                }
                
                
              }
            }

          className={`w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${internalPartyLoading ? 'opacity-80' : ''}`}
          placeholder="Search department / section / custom"
        />

        {open && (
          <div 
            onBlur={(e) => {
                if(!e.relatedTarget?.querySelector('internal_party')){
                  const exist = internalPartyOptions.find(x => { return x.label.trim().toLowerCase() === query.trim().toLowerCase() })
                  setOpen(false)
                  if(exist){
                    setFormData((prev) => ({ ...prev, internal_party: exist.value, coordinator: exist.label.trim(), in_party_type: exist.group }))
                    onChange(exist.label.trim())
                  }
                  else {
                    setFormData((prev) => ({ ...prev, internal_party: null, coordinator: query.trim(), in_party_type: 'custom' }))
                    onChange(query.trim())
                  }
                }
              }
            }
            className="absolute z-20 mt-2 w-full max-h-64 overflow-y-auto rounded-2xl border border-gray-200 dark:border-slate-700 bg-white dark:bg-slate-800 shadow-lg">
            {internalPartyLoading && (
              <div className="p-3 text-sm text-gray-500 dark:text-slate-300">Loading…</div>
            )}
            {!internalPartyLoading && !anyOptions && (
              <div className="p-3 text-sm text-gray-500 dark:text-slate-300">No options available</div>
            )}
            {!internalPartyLoading && anyOptions && (
              <div className="py-2">
                {filteredByGroup
                  .filter((g) => g.options.length > 0)
                  .map((group) => (
                    <div key={group.key}>
                      <div className="px-3 py-1.5 text-xs font-semibold text-gray-500 dark:text-slate-300 uppercase">
                        {group.key}
                      </div>
                      {group.options.map((opt) => (
                        <button
                          key={`${opt.group}|${opt.value}`}
                          type="button"
                          onClick={(e) => {
                            setQuery(opt.label);
                            setOpen(false);
                            onChange(opt.label);
                            setFormData((prev) => ({ ...prev, internal_party: opt.value, coordinator: opt.label, in_party_type: opt.group }))
                          }}

                          className={`internal_party w-full text-left px-3 py-2 text-sm hover:bg-gray-50 dark:hover:bg-slate-700 transition-all ${query.trim() === opt.label ? 'bg-gray-50 dark:bg-slate-700' : ''}`}
                        >
                          {opt.label}
                        </button>
                      ))}
                    </div>
                  ))}

                {/* If user typed something not among options, treat as custom */}
                {!internalPartyLoading && normalizedQuery && (
                  (() => {
                    const exact = internalPartyOptions.some((o) => o.label.toLowerCase() === normalizedQuery);
                    if (exact) return null;
                    return (
                      <div className="border-t border-gray-100 dark:border-slate-700 pt-2">
                        <button
                          type="button"
                          onClick={() => {
                            setOpen(false);
                            setQuery(query);
                            onChange(query);
                            setFormData((prev) => ({ ...prev, coordinator: query, in_party_type: 'custom' }))
                          }}

                          className="internal_party w-full text-left px-3 py-2 text-sm hover:bg-gray-50 dark:hover:bg-slate-700 transition-all"
                        >
                          Add “{query.trim()}” as custom coordinator
                        </button>
                      </div>
                    );
                  })()
                )}
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  const handleAddContractType = () => {
    if (isViewMode) return;
    setNewTypeForm({ name: '', description: '' });
    setAddTypeError('');
    setShowAddTypeDialog(true);
  };

  const handleNewTypeChange = (e) => {
    const { name, value } = e.target;
    setNewTypeForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleCreateNewType = async () => {
    const typeName = newTypeForm.name.trim();
    const typeDescription = newTypeForm.description.trim();
    if (!typeName) {
      setAddTypeError('Contract type name is required.');
      return;
    }

    setAddingType(true);
    setAddTypeError('');

    try {
      const newType = await createContractType(typeName, typeDescription);
      setContractTypes((prev) => {
        const exists = prev.some((type) => type.name === newType.name);
        if (exists) return prev;
        return [...prev, newType].sort((a, b) => a.name.localeCompare(b.name));
      });
      setFormData((prev) => ({ ...prev, contract_type: newType.name }));
      setShowAddTypeDialog(false);
    } catch (err) {
      console.error('Failed to create contract type:', err);
      setAddTypeError('Unable to create contract type. Please try again.');
    } finally {
      setAddingType(false);
    }
  };


  useEffect(() => {
    if (!isOpen) {
      // Reset on close
      setFormData({
        contract_number: '',
        contract_type: 'MOA',
        title: '',
        contractor: '',
        details: '',
        coordinator: '',
        internal_party: null,
        in_party_type: '',
        start_date: '',
        end_date: '',
        status: 'inactive',
      });
      setFiles([]);
      setExistingDocs([]);
      setShowAddTypeDialog(false);
      setNewTypeForm({ name: '', description: '' });
      setAddTypeError('');
      setAddingType(false);
      return;
    }

    if (initialData) {
      setFormData({
        contract_number: initialData.contract_number || '',
        contract_type: initialData.contract_type || 'Others',
        title: initialData.title || '',
        contractor: initialData.contractor || '',
        details: initialData.details || '',
        coordinator: initialData.coordinator || '',
        internal_party: initialData.internal_party ?? null,
        start_date: initialData.start_date || '',
        end_date: initialData.end_date || '',
        status: initialData.status || 'inactive',
      });

      // Fetch existing documents for view/edit mode
      if (initialData.id) {
        setDocsLoading(true);
        fetchContractDocuments(initialData.id)
          .then((data) => {
            setExistingDocs(data?.results[0]?.documents || []);
          })
          .catch((err) => {
            console.error('Failed to fetch documents:', err);
            setExistingDocs([]);
          })
          .finally(() => setDocsLoading(false));
      }
    }
  }, [isOpen, initialData]);

  // Fetch contract types on component mount
  useEffect(() => {
    const fetchContractTypes = async () => {
      try {
        const types = await getContractTypes();
        setContractTypes(types);
      } catch (error) {
        console.error('Failed to load contract types:', error);
      }
    };
    fetchContractTypes();
  }, []);

  const generateContractNumber = () => {
    const year = new Date().getFullYear();
    const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
    return `${year}-${random}`;
  };

  const handleInputChange = (e) => {
    if (isViewMode) return;
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e) => {
    if (isViewMode) return;
    const newFile = Array.from(e.target.files);

    setFiles(prevFiles => {
      const combined = [...prevFiles, ...newFile];
      return combined.filter((file, index, self) =>
        index === self.findIndex(
          f => f.name === file.name
            && f.size === file.size
            && f.lastModified === file.lastModified
        )
      );
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (isViewMode) return;
    const submitData = { ...formData };
    if (isCreateMode) {
      submitData.contract_number = formData.contract_number || generateContractNumber();
    }
    onSubmit(submitData, files, submitData.contract_type);
  };

  const getTitle = () => {
    if (isViewMode) return `View Contract — ${initialData?.contract_number || ''}`;
    if (isEditMode) return `Edit Contract — ${initialData?.contract_number || ''}`;
    return 'Create New Contract';
  };

  const getSubmitLabel = () => {
    if (isEditMode) return 'Save Changes';
    return 'Create Contract';
  };

  const formatFileSize = (bytes) => {
    if (!bytes) return '0 KB';
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${Math.round(bytes / 1024)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  };

  const getFileIcon = (mimeType) => {
    if (mimeType?.startsWith('image/')) return '🖼️';
    if (mimeType === 'application/pdf') return '📄';
    if (mimeType?.includes('word')) return '📝';
    if (mimeType?.includes('excel') || mimeType?.includes('sheet')) return '📊';
    return '📎';
  };

  const handleDeleteDocument = async (docId) => {
    if (!window.confirm('Are you sure you want to delete this document?')) return;
    try {
      await deleteDocument(docId);
      setExistingDocs((prev) => prev.filter((d) => d.id !== docId));
    } catch (err) {
      console.error('Failed to delete document:', err);
    }
  };

  const canDeleteDoc = isEditMode || isViewMode;
  
  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={getTitle()}
      size="4xl"
      footer={
        isViewMode ? (
          <div className="flex pt-4">
            <button
              onClick={onClose}
              className="flex-1 bg-gray-100 hover:bg-gray-200 dark:bg-slate-700 dark:hover:bg-slate-600 text-gray-900 dark:text-slate-200 font-medium py-3 px-6 rounded-2xl transition-all duration-200"
            >
              Close
            </button>
          </div>
        ) : (
          <div className="flex space-x-3 pt-4">
            <button
              onClick={onClose}
              className="flex-1 bg-gray-100 hover:bg-gray-200 dark:bg-slate-700 dark:hover:bg-slate-600 text-gray-900 dark:text-slate-200 font-medium py-3 px-6 rounded-2xl transition-all duration-200"
            >
              Cancel
            </button>
            <button
              onClick={handleSubmit}
              disabled={loading}
              className="flex-1 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-semibold py-3 px-6 rounded-2xl shadow-lg hover:shadow-xl transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center"
            >
              {loading ? (
                <>
                  <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                  </svg>
                  {isEditMode ? 'Saving...' : 'Creating...'}
                </>
              ) : (
                getSubmitLabel()
              )}
            </button>
          </div>
        )
      }
    >
      {error && (
        <div className="mb-6 p-4 bg-red-100 border border-red-400 rounded-2xl text-red-800 text-sm">
          {error}
        </div>
      )}

      <form className="space-y-6" onSubmit={handleSubmit}>
        {/* Contract Number */}
        <div>
          <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
            Contract Number {isCreateMode && '(Optional - auto-generates if blank)'}
          </label>
          <input
            type="text"
            name="contract_number"
            value={formData.contract_number}
            onChange={handleInputChange}
            readOnly={isViewMode}
            required={isCreateMode || isEditMode}
            className={`w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${(isViewMode || isEditMode) ? 'bg-gray-100 dark:bg-slate-700' : ''}`}
            placeholder="2024-001"
          />
        </div>

        {/* Title */}
        <div>
          <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
            Title {isCreateMode && '*'}
          </label>
          <input
            type="text"
            name="title"
            value={formData.title}
            onChange={handleInputChange}
            readOnly={isViewMode}
            required={isCreateMode || isEditMode}
            className={`w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${isViewMode ? 'bg-gray-100 dark:bg-slate-700 cursor-not-allowed' : ''}`}
          />
        </div>

        {/* Contractor */}
        <div>
          <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
            Contracting Party {isCreateMode && '*'}
          </label>
          <input
            type="text"
            name="contractor"
            value={formData.contractor}
            onChange={handleInputChange}
            readOnly={isViewMode}
            required={isCreateMode || isEditMode}
            className={`w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${isViewMode ? 'bg-gray-100 dark:bg-slate-700 cursor-not-allowed' : ''}`}
          />
        </div>
        
        {/* Coordinator */}
        <div>
          <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
            Internal Party / Coordinator
          </label>

          {isViewMode ? (
            <input
              type="text"
              readOnly
              value={formData.internal_party || formData.coordinator || ''}
              className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-gray-100 dark:bg-slate-700 text-gray-900 dark:text-slate-100 cursor-not-allowed"
            />
          ) : (
            <CoordinatorCombobox
              value={formData.coordinator}
              onChange={(nextValue) => {
                const exist = internalPartyOptions.find(x => { return x.label.trim().toLowerCase() === nextValue.trim().toLowerCase()})
                if (exist){
                  setFormData((prev) => ({ ...prev, coordinator: exist.label, in_party_type: exist.group, internal_party: exist.value }));
                }
                else setFormData((prev) => ({ ...prev, coordinator: nextValue }));
              }}
            />

          )}
        </div>

        {/* Contract Type */}
        <div>
          <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
            Contract Type
          </label>
          {isViewMode ? (
            <input
              type="text"
              value={formData.contract_type}
              readOnly
              className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-gray-100 dark:bg-slate-700 text-gray-900 dark:text-slate-100 cursor-not-allowed"
            />
          ) : (
            <div className="space-y-3">
              <div className="flex items-center gap-2">
                <select
                  name="contract_type"
                  value={formData.contract_type}
                  onChange={handleInputChange}
                  className="flex-1 px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all"
                >
                  {contractTypes.map((type) => (
                    <option key={type.name} value={type.name}>
                      {type.name}
                    </option>
                  ))}
                </select>
                <button
                  type="button"
                  onClick={handleAddContractType}
                  className="h-12 w-12 flex items-center justify-center rounded-2xl border border-gray-300 dark:border-slate-600 bg-gray-50 dark:bg-slate-800 text-gray-700 dark:text-slate-200 hover:bg-gray-100 dark:hover:bg-slate-700 transition-all"
                  title="Add new contract type"
                >
                  +
                </button>
              </div>

              {showAddTypeDialog && (
                <div className="rounded-3xl border border-emerald-200 dark:border-emerald-800 bg-emerald-50 dark:bg-emerald-900/30 p-5 shadow-sm">
                  <div className="flex items-start justify-between gap-4">
                    <div>
                      <h3 className="text-lg font-semibold text-gray-900 dark:text-slate-100">Add Contract Type</h3>
                      <p className="text-sm text-gray-600 dark:text-slate-300 mt-1">Enter the new contract type name and an optional description.</p>
                    </div>
                    <button
                      type="button"
                      onClick={() => setShowAddTypeDialog(false)}
                      className="text-gray-500 hover:text-gray-700 dark:text-slate-300 dark:hover:text-slate-100"
                      title="Cancel add contract type"
                    >
                      ✕
                    </button>
                  </div>
                  <div className="mt-4 grid gap-4">
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">Name</label>
                      <input
                        type="text"
                        name="name"
                        value={newTypeForm.name}
                        onChange={handleNewTypeChange}
                        className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all"
                        placeholder="Enter a contract type name"
                        autoFocus
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">Description</label>
                      <textarea
                        name="description"
                        value={newTypeForm.description}
                        onChange={handleNewTypeChange}
                        rows="3"
                        className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all resize-vertical"
                        placeholder="Optional description for this contract type"
                      />
                    </div>
                  </div>
                  {addTypeError && (
                    <p className="mt-3 text-sm text-red-600 dark:text-red-400">{addTypeError}</p>
                  )}
                  <div className="mt-5 flex justify-end gap-3">
                    <button
                      type="button"
                      onClick={() => setShowAddTypeDialog(false)}
                      className="rounded-2xl border border-gray-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-gray-700 dark:text-slate-200 px-4 py-2 hover:bg-gray-100 dark:hover:bg-slate-600 transition-all"
                    >
                      Cancel
                    </button>
                    <button
                      type="button"
                      onClick={handleCreateNewType}
                      disabled={addingType}
                      className="rounded-2xl bg-emerald-500 hover:bg-emerald-600 text-white px-4 py-2 transition-all disabled:opacity-60 disabled:cursor-not-allowed"
                    >
                      {addingType ? 'Creating…' : 'Create Type'}
                    </button>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Dates */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
              Start Date {isCreateMode && '*'}
            </label>
            <input
              type="date"
              name="start_date"
              value={formData.start_date}
              onChange={handleInputChange}
              readOnly={isViewMode}
              required={isCreateMode}
              className={`w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${isViewMode ? 'bg-gray-100 dark:bg-slate-700 cursor-not-allowed' : ''}`}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
              End Date {isCreateMode && '*'}
            </label>
            <input
              type="date"
              name="end_date"
              value={formData.end_date}
              onChange={handleInputChange}
              readOnly={isViewMode}
              required={isCreateMode}
              className={`w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${isViewMode ? 'bg-gray-100 dark:bg-slate-700 cursor-not-allowed' : ''}`}
            />
          </div>
        </div>

        {/* Status */}
        <div>
          <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
            Status
          </label>
          {isViewMode ? (
            <input
              type="text"
              value={formData.status.toUpperCase()}
              readOnly
              className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-gray-100 dark:bg-slate-700 text-gray-900 dark:text-slate-100 cursor-not-allowed"
            />
          ) : (
            <select
              name="status"
              value={formData.status}
              onChange={handleInputChange}
              className="w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all"
            >
              <option value="inactive">Inactive</option>
              <option value="active">Active</option>
            </select>
          )}
        </div>

        {/* Existing Documents Section — Separated from upload area */}
        {(isViewMode || isEditMode) && (
          <div>
            <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-3">
              Existing Documents ({existingDocs.length})
            </label>
            <div className="border border-gray-200 dark:border-slate-600 rounded-2xl p-4 bg-gray-50 dark:bg-slate-800/50">
              {docsLoading ? (
                <div className="flex items-center justify-center py-4 space-x-2 text-sm text-gray-500">
                  <svg className="animate-spin h-4 w-4 text-emerald-500" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  <span>Loading documents...</span>
                </div>
              ) : existingDocs.length === 0 ? (
                <p className="text-sm text-gray-500 dark:text-slate-400 text-center py-2">No documents uploaded yet.</p>
              ) : (
                <div className="space-y-2 max-h-48 overflow-y-auto">
                  {existingDocs.map((doc) => (
                    <div
                      key={doc.id}
                      className="flex items-center justify-between p-3 bg-white dark:bg-slate-700 border border-gray-200 dark:border-slate-600 rounded-xl"
                    >
                      <div className="flex items-center space-x-3 overflow-hidden">
                        <span className="text-lg">{getFileIcon(doc.mime_type)}</span>
                        <div className="min-w-0">
                          <p className="text-sm font-medium text-gray-800 dark:text-slate-200 truncate" title={doc.original_filename || doc.document_name}>
                            {doc.original_filename || doc.document_name}
                          </p>
                          <p className="text-xs text-gray-500 dark:text-slate-400">
                            {formatFileSize(doc.file_size)}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-1 shrink-0">
                        <a
                          href={getDocumentViewUrl(doc)}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="ml-2 text-xs font-semibold text-emerald-600 hover:text-emerald-800 dark:text-emerald-400 dark:hover:text-emerald-200 px-3 py-1.5 rounded-lg hover:bg-emerald-50 dark:hover:bg-emerald-900/30 transition-all"
                          title="Download"
                        >
                          Download
                        </a>
                        {!isViewMode && canDeleteDoc && (
                          <button
                            type="button"
                            onClick={() => handleDeleteDocument(doc.id)}
                            className="p-1.5 text-red-500 hover:text-red-700 hover:bg-red-100 dark:hover:bg-red-900/30 rounded-lg transition-all"
                            title="Delete document"
                          >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        {/* File Upload — Only for create/edit mode */}
        {(isCreateMode || isEditMode) && (
          <div>
            <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-4">
              {isEditMode ? 'Upload New Documents' : 'Upload Documents'} (PDF, DOCX, Images)
            </label>
            <div className="border-2 border-dashed border-gray-300 dark:border-slate-600 rounded-3xl p-10 text-center hover:border-emerald-400 hover:shadow-lg transition-all duration-300 cursor-pointer">
              <input
                type="file"
                multiple
                accept=".pdf,.doc,.docx,.png,.jpg,.jpeg,.gif"
                onChange={handleFileChange}
                className="hidden"
                id="file-upload"
              />
              <label htmlFor="file-upload" className="cursor-pointer">
                <svg className="w-16 h-16 mx-auto mb-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                </svg>
                <p className="text-lg font-semibold text-gray-700 dark:text-slate-300 mb-1">
                  {files.length > 0 ? `${files.length} files selected` : 'Click to upload or drag & drop'}
                </p>
                <p className="text-sm text-gray-500 dark:text-slate-500">Max 10MB per file</p>
              </label>

              {files.length > 0 && (
                <div className="mt-6 space-y-2">
                  {files.map((file, index) => (
                    <div key={index} className="flex items-center justify-between p-3 bg-emerald-50 dark:bg-emerald-900/30 border border-emerald-200 dark:border-emerald-800/50 rounded-xl">
                      <span className="text-sm font-medium text-emerald-800 dark:text-emerald-200 truncate flex-1 mr-2">
                        <span className="ml-2 text-xs bg-emerald-200 dark:bg-emerald-800/50 px-2 py-0.5 rounded-full">
                          {Math.round(file.size / 1024)} KB
                        </span>
                        {file.name.length > 30 ? file.name.slice(0, 30) + '...' : file.name}
                      </span>
                      <button
                        type="button"
                        onClick={() => setFiles(prev => prev.filter((_, i) => i !== index))}
                        className="p-1.5 hover:bg-red-100 dark:hover:bg-red-900/30 rounded-lg transition-all text-red-600 hover:text-red-700"
                        title="Remove file"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                        </svg>
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
            <p className="text-xs text-gray-500 dark:text-slate-500 mt-2 text-center">
              Files stored as: documents/contractType/contractNumber/filename.ext
            </p>
          </div>
        )}

        {/* Details */}
        <div>
          <label className="block text-sm font-semibold text-gray-700 dark:text-slate-300 mb-2">
            Details / Remarks
          </label>
          <textarea
            name="details"
            value={formData.details}
            onChange={handleInputChange}
            readOnly={isViewMode}
            rows="3"
            className={`w-full px-4 py-3 border border-gray-300 dark:border-slate-600 rounded-2xl bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all resize-vertical ${isViewMode ? 'bg-gray-100 dark:bg-slate-700 cursor-not-allowed' : ''}`}
            placeholder="Additional details, terms, or special notes..."
          />
        </div>
      </form>
    </Modal>
  );
};

export default ContractModal;
