import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import { fetchDeletedContracts, restoreContract, deleteContract } from '../../services/api';

const DeletedContractsModal = ({ isOpen, onClose, onSuccess }) => {
  const [deletedContracts, setDeletedContracts] = useState([]);
  const [selectedContractIds, setSelectedContractIds] = useState([]);
  const [loading, setLoading] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!isOpen) {
      setDeletedContracts([]);
      setSelectedContractIds([]);
      setError('');
      return;
    }

    setLoading(true);
    setError('');
    setSelectedContractIds([]);

    fetchDeletedContracts({ limit: 100, offset: 0, sort_by: 'deleted_at', sort_order: 'desc' })
      .then((data) => {
        setDeletedContracts(data.results || []);
      })
      .catch((err) => {
        console.error('Failed to load deleted contracts:', err);
        setError('Unable to load deleted contracts at this time.');
      })
      .finally(() => setLoading(false));
  }, [isOpen]);

  const formatTimestamp = (timestamp) => {
    if (!timestamp) return 'N/A';
    const date = new Date(timestamp);
    return date.toLocaleString();
  };

  const isAllSelected = deletedContracts.length > 0 && selectedContractIds.length === deletedContracts.length;

  const toggleSelectAll = (event) => {
    if (event.target.checked) {
      setSelectedContractIds(deletedContracts.map((contract) => contract.id));
    } else {
      setSelectedContractIds([]);
    }
  };

  const toggleSelectContract = (id) => {
    setSelectedContractIds((current) =>
      current.includes(id) ? current.filter((selectedId) => selectedId !== id) : [...current, id]
    );
  };

  const refreshDeletedContracts = async () => {
    setLoading(true);
    setError('');
    try {
      const data = await fetchDeletedContracts({ limit: 100, offset: 0, sort_by: 'deleted_at', sort_order: 'desc' });
      setDeletedContracts(data.results || []);
      setSelectedContractIds([]);
    } catch (err) {
      console.error('Failed to reload deleted contracts:', err);
      setError('Unable to refresh deleted contracts.');
    } finally {
      setLoading(false);
    }
  };

  const handleRestoreSelected = async () => {
    if (selectedContractIds.length === 0) {
      window.alert('Please select at least one contract to restore.');
      return;
    }

    setProcessing(true);
    setError('');

    try {
      await restoreContract(selectedContractIds);
      await refreshDeletedContracts();
      if (onSuccess) await onSuccess();
    } catch (err) {
      console.error('Failed to restore contracts:', err);
      setError('Unable to restore selected contracts.');
    } finally {
      setProcessing(false);
    }
  };

  const handleDeleteSelected = async () => {
    if (selectedContractIds.length === 0) {
      window.alert('Please select at least one contract to delete.');
      return;
    }

    if (!window.confirm('This will permanently delete the selected contracts.\n\nAll documents tied to this contract will also be deleted.\nAnd this action can no longer be undone.\n\nDo yo hereby confirm to delete these records?')) {
      return;
    }

    setProcessing(true);
    setError('');

    try {
      await deleteContract(selectedContractIds);
      await refreshDeletedContracts();
      if (onSuccess) await onSuccess();
    } catch (err) {
      console.error('Failed to delete contracts:', err);
      setError('Unable to delete selected contracts.');
    } finally {
      setProcessing(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Deleted Contracts"
      size="6xl"
      footer={
        <div className="flex items-center justify-between gap-3 pt-4">
          <div className="text-sm text-slate-600 dark:text-slate-400 flex gap-3">
            <button 
              onClick={handleRestoreSelected}
              disabled={processing || selectedContractIds.length === 0}
              className={`bg-emerald-500 hover:bg-emerald-600 text-white font-medium py-3 px-6 rounded-2xl transition-all duration-200 ${processing || selectedContractIds.length === 0 ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
              Restore
            </button>
            <button 
                onClick={handleDeleteSelected}
                disabled={processing || selectedContractIds.length === 0}
                className={`bg-red-500 hover:bg-red-600 text-white font-medium py-3 px-6 rounded-2xl transition-all duration-200 ${processing || selectedContractIds.length === 0 ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
                Delete
            </button>

            {selectedContractIds.length > 0 ? (
              <span className="content-center">
                {selectedContractIds.length} selected
              </span>
            ) : (
              <span className="content-center">No contracts selected</span>
            )}
            
          </div>
          <div className="flex items-center gap-3">
            
            <button
                onClick={onClose}
                className="bg-gray-100 hover:bg-gray-200 dark:bg-slate-700 dark:hover:bg-slate-600 text-gray-900 dark:text-slate-100 font-medium py-3 px-6 rounded-2xl transition-all duration-200"
            >
                Close
            </button>
          </div>
        </div>
      }
    >
      <div className="space-y-4">
        <p className="text-sm text-slate-500 dark:text-slate-400">
          Showing contracts that were marked for deletion. Deleted contracts are stored for review and can be removed automatically by backend cleanup.
        </p>

        {loading ? (
          <div className="text-center py-8">
            <span className="text-gray-600 dark:text-slate-300">Loading deleted contracts...</span>
          </div>
        ) : error ? (
          <div className="text-red-600 dark:text-red-400 bg-red-100 dark:bg-red-900/40 rounded-2xl p-4">
            {error}
          </div>
        ) : deletedContracts.length === 0 ? (
          <div className="text-center py-8 text-gray-600 dark:text-slate-300">
            No deleted contracts found.
          </div>
        ) : (
          <div className="overflow-x-auto rounded-3xl border border-slate-200 dark:border-slate-700">
            <table className="min-w-full text-left">
              <thead className="bg-slate-100 dark:bg-slate-900">
                <tr>
                  <th className="px-4 py-3 text-sm font-semibold uppercase text-slate-600 dark:text-slate-300">
                    <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-semibold bg-red-100 text-red-800">
                        <input id="selectAll" type="checkbox" className="cursor-pointer form-checkbox h-4 w-4 text-red-600" checked={isAllSelected} onChange={toggleSelectAll} />
                    </span>
                  </th>
                  <th className="px-4 py-3 text-sm font-semibold uppercase text-slate-600 dark:text-slate-300">Contract #</th>
                  <th className="px-4 py-3 text-sm font-semibold uppercase text-slate-600 dark:text-slate-300">Title</th>
                  <th className="px-4 py-3 text-sm font-semibold uppercase text-slate-600 dark:text-slate-300">Contracting Party</th>
                  <th className="px-4 py-3 text-sm font-semibold uppercase text-slate-600 dark:text-slate-300">Status</th>
                  <th className="px-4 py-3 text-sm font-semibold uppercase text-slate-600 dark:text-slate-300">Type</th>
                  <th className="px-4 py-3 text-sm font-semibold uppercase text-slate-600 dark:text-slate-300">Deleted At</th>
                  <th className="px-4 py-3 text-sm font-semibold uppercase text-slate-600 dark:text-slate-300 text-center">Documents</th>
                </tr>
              </thead>
              <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                {deletedContracts.map((contract) => (
                  <tr key={contract.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/60 transition-colors">
                    <td className="px-4 py-4 text-sm font-medium text-slate-900 dark:text-slate-100">
                        <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-semibold bg-red-100 text-red-800">
                            <input
                              type="checkbox"
                              className="cursor-pointer form-checkbox h-4 w-4 text-red-600"
                              checked={selectedContractIds.includes(contract.id)}
                              onChange={() => toggleSelectContract(contract.id)}
                              value={contract.id}
                            />
                        </span>
                    </td>
                    <td className="px-4 py-4 text-sm font-medium text-slate-900 dark:text-slate-100">{contract.contract_number}</td>
                    <td className="px-4 py-4 text-sm text-slate-700 dark:text-slate-300 truncate max-w-xs">{contract.title}</td>
                    <td className="px-4 py-4 text-sm text-slate-700 dark:text-slate-300 truncate max-w-xs">{contract.contractor}</td>
                    <td className="px-4 py-4 text-sm text-slate-700 dark:text-slate-300 truncate max-w-xs">{contract.status}</td>
                    <td className="px-4 py-4 text-sm text-slate-700 dark:text-slate-300">{contract.contract_type || 'N/A'}</td>
                    <td className="px-4 py-4 text-sm text-slate-700 dark:text-slate-300">{formatTimestamp(contract.deleted_at)}</td>
                    <td className="px-4 py-4 text-sm text-slate-700 dark:text-slate-300 text-center">{contract.documents_count || 0}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </Modal>
  );
};

export default DeletedContractsModal;
