import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import { getDocumentViewUrl } from '../../services/api';

const DocumentViewerModal = ({ isOpen, onClose, document: doc }) => {
  if (!doc) return null;

  const url = getDocumentViewUrl(doc);
  const isImage = doc.mime_type?.startsWith('image/');
  const isPdf = doc.mime_type === 'application/pdf';
  const title = doc.original_filename || doc.document_name || 'Document Viewer';

  const handleDownload = () => {
    if (!url) return;
    window.open(url, '_blank');
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={title}
      size="4xl"
      footer={
        <div className="flex justify-between items-center pt-2 sticky bottom-[10%]">
          <span className="text-sm text-gray-500 dark:text-slate-400 truncate max-w-xs">
            {doc.file_type_label || doc.mime_type}
          </span>
          <button
            onClick={handleDownload}
            className="flex items-center space-x-2 bg-gradient-to-r from-indigo-500 to-purple-600 hover:from-indigo-600 hover:to-purple-700 text-white font-semibold py-2 px-6 rounded-2xl shadow-lg hover:shadow-xl transition-all duration-200"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
            <span>Download</span>
          </button>
        </div>
      }
    >
      <div className="flex items-center justify-center min-h-[50vh]">
        {isImage ? (
          <img
            src={url}
            alt={title}
            className="max-w-full max-h-[70vh] object-contain rounded-2xl shadow-lg"
          />
        ) : isPdf ? (
          <object
            data={url}
            title={title}
            type="application/pdf"
            className="w-full h-[70vh] rounded-2xl border border-gray-200 dark:border-slate-600"
          />
        ) : (
          <div className="text-center py-12">
            <svg className="w-16 h-16 mx-auto mb-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
            <p className="text-gray-600 dark:text-slate-400 mb-4">This file type cannot be previewed.</p>
            <button
              onClick={handleDownload}
              className="bg-gradient-to-r from-indigo-500 to-purple-600 hover:from-indigo-600 hover:to-purple-700 text-white font-semibold py-2 px-6 rounded-2xl shadow-lg hover:shadow-xl transition-all duration-200"
            >
              Download File
            </button>
          </div>
        )}
      </div>
    </Modal>
  );
};

export default DocumentViewerModal;
