import React, { useState, useEffect } from 'react';
import { Counter, useDeletedContractsModal, useContractModal, fetchContracts, getContractTypes, scheduleContractDeletion } from '../services/api';
import { Icon } from '../components/icons';

const useDebounce = (value, delay) => {
  const [debouncedValue, setDebouncedValue] = useState(value);
  useEffect(() => {
    const handler = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(handler);
  }, [value, delay]);
  return debouncedValue;
};

const Contracts = ({ initialConfig, onConfigChange }) => {
  const config = {
    searchQuery: initialConfig?.searchQuery || '',
    filterStatus: initialConfig?.filterStatus || 'all',
    filterType: initialConfig?.filterType || 'all',
    sortConfig: initialConfig?.sortConfig || { key: 'contract_number', direction: 'desc' }
  };

  const { openContractModal, openViewContractModal, openEditContractModal } = useContractModal();
  const { openDeletedContractsModal } = useDeletedContractsModal();
  const [contracts, setContracts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [error, setError] = useState('');
  const [contractTypes, setContractTypes] = useState([]);
  const [searchQuery, setSearchQuery] = useState(config.searchQuery);
  const [filterStatus, setFilterStatus] = useState(config.filterStatus);
  const [filterType, setFilterType] = useState(config.filterType);
  const [sortConfig, setSortConfig] = useState(config.sortConfig);
  const [hasMore, setHasMore] = useState(false);
  const debouncedSearch = useDebounce(searchQuery, 500);
  const [deleted_contracts, setDeletedContracts] = useState(0);

  const [fetchParams, setFetchParams] = useState({
    offset: 0,
    search: config.searchQuery,
    status: config.filterStatus,
    contract_type: config.filterType,
    sort_by: config.sortConfig.key,
    sort_order: config.sortConfig.direction
  });
  
  // Track whether state changes are from user interaction (not from initialConfig)
  const onConfigChangeRef = React.useRef(onConfigChange);
  onConfigChangeRef.current = onConfigChange;
  const isUserDriven = React.useRef(false);

  // Save config changes to parent whenever user-driven state changes
  useEffect(() => {
    if (!isUserDriven.current) {
      isUserDriven.current = true;
      return;
    }
    onConfigChangeRef.current?.({
      searchQuery,
      filterStatus,
      filterType,
      sortConfig
    });
  }, [searchQuery, filterStatus, filterType, sortConfig]);

  // Fetch contract types on component mount
  useEffect(() => {
    const doFetch = async () => {
      try {
        const types = await getContractTypes();
        setContractTypes(types);
      } catch (error) {
        console.error('Failed to load contract types:', error);
      }
    };
    doFetch();
  }, []);

  useEffect(() => {
    setFetchParams({
      offset: 0,
      search: debouncedSearch,
      status: filterStatus,
      contract_type: filterType,
      sort_by: sortConfig.key,
      sort_order: sortConfig.direction
    });
  }, [debouncedSearch, filterStatus, filterType, sortConfig]);

  useEffect(() => {
    const doFetch = async () => {
      const isInitial = fetchParams.offset === 0;
      if (isInitial) setLoading(true);
      else setLoadingMore(true);

      try {
        const params = {
          limit: 10,
          offset: fetchParams.offset,
          ...(fetchParams.search && { search: fetchParams.search }),
          ...(fetchParams.status !== 'all' && { status: fetchParams.status }),
          ...(fetchParams.contract_type !== 'all' && { contract_type: fetchParams.contract_type }),
          sort_by: fetchParams.sort_by,
          sort_order: fetchParams.sort_order
        };

        const data = await fetchContracts(params);
        if (isInitial) {
          setContracts(data.results);
        } else {
          setContracts(prev => [...prev, ...data.results]);
        }
        setHasMore(data.has_more);
        setDeletedContracts(data.deleted_contracts)
        setError('');
      } catch (err) {
        if (isInitial) setError(err.message);
      } finally {
        if (isInitial) setLoading(false);
        else setLoadingMore(false);
      }
    };

    doFetch();
  }, [fetchParams]);

  const refreshContracts = async () => {
    setLoading(true);
    setError('');

    try {
      const params = {
        limit: 10,
        offset: 0,
        ...(fetchParams.search && { search: fetchParams.search }),
        ...(fetchParams.status !== 'all' && { status: fetchParams.status }),
        ...(fetchParams.contract_type !== 'all' && { contract_type: fetchParams.contract_type }),
        sort_by: fetchParams.sort_by,
        sort_order: fetchParams.sort_order,
      };

      const data = await fetchContracts(params);
      setContracts(data.results || []);
      setHasMore(data.has_more);
      setDeletedContracts(data.deleted_contracts || 0);
      setFetchParams(prev => ({ ...prev, offset: 0 }));
      setError('');
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleLoadMore = () => {
    setFetchParams(prev => ({
      ...prev,
      offset: contracts.length
    }));
  };

  const handleSort = (key) => {
    setSortConfig((prev) => {
      if (prev.key === key) {
        return { key, direction: prev.direction === 'asc' ? 'desc' : 'asc' };
      }
      return { key, direction: 'asc' };
    });
  };

  const getSortIcon = (key) => {
    const iconClass = 'w-3 h-3 inline';
    if (sortConfig.key !== key) {
      return (
        <svg className={`${iconClass} opacity-40`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4-4" />
        </svg>
      );
    }
    return sortConfig.direction === 'asc' ? (
      <svg className={iconClass} fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" />
      </svg>
    ) : (
      <svg className={iconClass} fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
      </svg>
    );
  };

  const statusColors = {
    active: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/50 dark:text-emerald-200',
    inactive: 'bg-amber-100 text-amber-800 dark:bg-amber-900/50 dark:text-amber-200',
    expired: 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-200',
    completed: 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-200',
    deleted: 'bg-red-100 text-red-800 dark:bg-red-900/50 dark:text-red-200',
  };

  const SortHeader = ({ label, sortKey, align = 'left' }) => (
    <th
      className={`px-6 py-4 text-${align} font-bold text-white hover:bg-teal-700/60 hover:shadow-xl uppercase tracking-wider cursor-pointer transition-colors select-none`}
      onClick={() => handleSort(sortKey)}
    >
      <div className={`inline-flex items-center font-bold relative ${align === 'center' ? 'justify-center' : ''}`}>
        <span>{label}</span>
        <span className="absolute left-full ml-1">{getSortIcon(sortKey)}</span>
      </div>
    </th>
  );

  const hasActiveFilters = debouncedSearch || filterStatus !== 'all' || filterType !== 'all';

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <button
          onClick={() => openContractModal(() => setFetchParams(prev => ({ ...prev, offset: 0 })))}
          className="bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-semibold py-3 px-8 rounded-2xl shadow-lg hover:shadow-xl transition-all duration-200"
        >
          + New Contract
        </button>

        { deleted_contracts ? 
          <button className="bg-gradient-to-r from-orange-800 to-red-800 py-3 px-4 rounded-2xl flex items-center justify-center">
            <Icon onClick={() => openDeletedContractsModal(refreshContracts)} name="delete" className="w-6 h-6 text-white" />
          </button>
          : <></>
        }
      </div>

      {/* Search & Filter Bar */}
      <div className="flex flex-col sm:flex-row gap-4">
        <div className="relative flex-1">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <svg className="h-5 w-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
          <input
            type="text"
            placeholder="Search contracts..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 dark:border-slate-600 rounded-xl leading-5 bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm transition-colors"
          />
        </div>
        <select
          value={filterStatus}
          onChange={(e) => setFilterStatus(e.target.value)}
          className="block w-full sm:w-44 pl-3 pr-8 py-2.5 border border-gray-200 dark:border-slate-600 rounded-xl leading-5 bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm transition-colors cursor-pointer"
        >
          <option value="all">All Statuses</option>
          <option value="active">Active</option>
          <option value="inactive">Inactive</option>
          <option value="completed">Completed</option>
          <option value="expired">Expired</option>
          <option value="expiring_soon">Expiring/Completing Soon</option>
        </select>
        <select
          value={filterType}
          onChange={(e) => setFilterType(e.target.value)}
          className="block w-full sm:w-56 pl-3 pr-8 py-2.5 border border-gray-200 dark:border-slate-600 rounded-xl leading-5 bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm transition-colors cursor-pointer"
        >
          <option value="all">All Contract Types</option>
          {contractTypes.map((type) => (
            <option key={type.name} value={type.name}>{type.name}</option>
          ))}
        </select>
        <button
          onClick={() => {
            setSearchQuery('');
            setFilterStatus('all');
            setFilterType('all');
          }}
          className={`px-4 py-2 rounded-xl text-sm font-semibold bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white ${!hasActiveFilters ? 'opacity-50 cursor-not-allowed' : ''}`}
          disabled={!hasActiveFilters}
        >
          Clear Filters
        </button>
      </div>

      {/* Contracts Table */}
      <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-gray-200 dark:border-slate-700 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="bg-gradient-to-r from-emerald-500 to-teal-800 border-b border-gray-200 dark:border-slate-600">
                <th className="px-6 py-4 text-center font-bold text-white uppercase tracking-wider">
                  #
                </th>
                <SortHeader label="Contract #" sortKey="contract_number" align="center" />
                <SortHeader label="Title" sortKey="title" align="left" />
                <SortHeader label="Contracting Party" sortKey="contractor" align="center" />
                <SortHeader label="Type" sortKey="contract_type" align="center" />
                <SortHeader label="Status" sortKey="status" align="center" />
                <SortHeader label="Start Date" sortKey="start_date" align="center" />
                <SortHeader label="End Date" sortKey="end_date" align="center" />
                <SortHeader label="Remaining Days" sortKey="remaining_days" align="center" />
                <SortHeader label="Docs" sortKey="documents_count" align="center" />
                <th className="px-6 py-4 text-center font-bold text-white uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-slate-700">
              {loading ? (
                <tr>
                  <td className="px-6 py-8 text-sm text-gray-600 dark:text-slate-400 text-center" colSpan="12">
                    <div className="flex items-center justify-center space-x-2">
                      <svg className="animate-spin h-5 w-5 text-emerald-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      <span>Loading contracts...</span>
                    </div>
                  </td>
                </tr>
              ) : error ? (
                <tr>
                  <td className="px-6 py-8 text-sm text-red-500 text-center" colSpan="12">
                    Error: {error}
                  </td>
                </tr>
              ) : contracts.length === 0 ? (
                <tr>
                  <td className="px-6 py-8 text-sm text-gray-600 dark:text-slate-400 text-center" colSpan="12">
                    {hasActiveFilters ? 'No contracts match your search' : 'No contracts created yet'}
                  </td>
                </tr>
              ) : (
                <>
                  {contracts.map((contract, count) => {
                    const isForDelete = contract.deleted_at !== null && contract.deleted_at !== undefined;
                      return (
                      <tr
                        id={`contract-${contract.id}`}
                        key={contract.id}
                        className={`transition-colors ${isForDelete ? 'grayscale opacity-50 bg-slate-200' : 'hover:bg-gray-50 dark:hover:bg-slate-700/50' }`}
                      >
                        <td className="px-6 py-5 text-center text-gray-400 dark:text-slate-500">
                          {++count}
                        </td>
                      <td className="px-6 py-5 font-mono text-sm font-semibold text-gray-900 dark:text-slate-100 text-center">
                        {contract.contract_number}
                      </td>
                      <td className="px-6 py-5">
                        <div className="text-sm font-semibold text-gray-900 dark:text-slate-100 truncate max-w-xs" title={contract.title}>
                          {contract.title}
                        </div>
                      </td>
                      <td className="px-6 py-5 text-sm text-gray-700 dark:text-slate-300 text-center">{contract.contractor}</td>
                      <td className="px-6 py-5 text-center">
                        <span className="inline-flex px-3 py-1 rounded-full text-sm font-semibold bg-indigo-100 dark:bg-indigo-900/50 text-indigo-800 dark:text-indigo-200">
                          {contract.contract_type || 'N/A'}
                        </span>
                      </td>
                      <td className="px-6 py-5 text-center">
                        <span className={`inline-flex px-3 py-1 rounded-full text-sm font-bold ${statusColors[contract.remaining_days < 0 ? (contract.status.toLowerCase() === 'active' ? 'completed' : 'expired') 
                                                                      : contract.status?.toLowerCase()] || 'bg-gray-100 text-gray-800 dark:bg-slate-700 dark:text-slate-300'}`}>
                          {isForDelete ? 'DELETED' 
                                       : (contract.remaining_days < 0 ? (contract.status.toLowerCase() === 'active' ? 'COMPLETED' : 'EXPIRED') 
                                                                      : contract.status?.toUpperCase())
                          }
                        </span>
                      </td>
                      <td className="px-6 py-5 text-sm text-gray-600 dark:text-slate-400 text-center">{contract.start_date}</td>
                      <td className="px-6 py-5 text-sm text-gray-600 dark:text-slate-400 text-center">{contract.end_date}</td>
                      <td className={`px-6 py-5 text-sm text-center font-bold ${contract.status?.toLowerCase() === 'inactive' ? 'text-orange-500' : contract.remaining_days >= 0 || (contract.status?.toLowerCase() === 'active') ? 'text-emerald-500' : 'text-red-500'}`}>
                        {contract.remaining_days > 1 ? `${contract.remaining_days} days` : contract.remaining_days >= 0 ? `${contract.remaining_days} day` : contract.status == 'active' ? 'Completed' : 'Expired'}
                      </td>
                      <td className="px-6 py-5 text-center">
                        <span className="text-sm font-medium text-indigo-600 dark:text-indigo-400">{contract.documents_count || 0}</span>
                      </td>
                      <td className="px-6 py-5 text-center text-sm font-medium space-x-2">
                        <button
                          onClick={() => {openViewContractModal(contract)}}
                          className="text-purple-600 dark:text-purple-400 hover:text-purple-900 dark:hover:text-purple-300 p-2 rounded-xl hover:bg-purple-100 dark:hover:bg-purple-900/30 transition-all"
                          title="View Contract"
                        >
                          <Icon name="view" className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => openEditContractModal(contract, () => setFetchParams(prev => ({ ...prev, offset: 0 })))}
                          className="text-emerald-600 dark:text-emerald-400 hover:text-emerald-900 dark:hover:text-emerald-300 p-2 rounded-xl hover:bg-emerald-100 dark:hover:bg-emerald-900/30 transition-all"
                          title="Edit Contract"
                        >
                          <Icon name="edit" className="w-4 h-4" />
                        </button>
                        <button
                          onClick={async () => {
                            if (!window.confirm('Are you sure you want to mark this contract for deletion?')) {
                              return;
                            }
                            try {
                              const updated = await scheduleContractDeletion(contract.id);
                              setContracts(prev => prev.map((item) => item.id === contract.id ? updated : item));
                              setDeletedContracts(deleted_contracts+1)
                              alert('The record has been marked as deleted.');
                            } catch (err) {
                              console.error(err);
                              alert('Failed to mark the contract for deletion.');
                            }
                          }}
                          className="text-red-600 dark:text-red-400 hover:text-red-900 dark:hover:text-red-300 p-2 rounded-xl hover:bg-red-100 dark:hover:bg-red-900/30 transition-all"
                          title="Delete Contract"
                        >
                          <Icon name="delete" className="w-4 h-4" />
                        </button>
                      </td>
                    </tr>
                    );
                  })}
                  <tr className="bg-gray-50 dark:bg-slate-700/30">
                    <td colSpan="11" className="px-6 py-4 text-center">
                      {loadingMore ? (
                        <div className="flex items-center justify-center space-x-2">
                          <svg className="animate-spin h-4 w-4 text-emerald-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                          </svg>
                          <span className="text-sm text-gray-600 dark:text-slate-400">Loading more...</span>
                        </div>
                      ) : hasMore ? (
                        <button
                          onClick={handleLoadMore}
                          className="text-sm font-semibold text-emerald-600 hover:text-emerald-800 dark:text-emerald-400 dark:hover:text-emerald-200 py-2 px-6 rounded-xl hover:bg-emerald-50 dark:hover:bg-emerald-900/20 transition-colors cursor-pointer"
                        >
                          Load More
                        </button>
                      ) : (
                        <span className="text-sm text-gray-400 dark:text-slate-500 italic">
                          — Nothing Follows —
                        </span>
                      )}
                    </td>
                  </tr>
                </>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Contracts;

