import React, { useState } from 'react';
import { ModalProvider } from './context/ModalContext';
import Sidebar from './components/Sidebar';
import Footer from './components/Footer';
import Header from './components/Header';
import Dashboard from './pages/Dashboard';
import Contracts from './pages/Contracts';
import Documents from './pages/Documents';
import Analytics from './pages/Analytics';
import Recents from './pages/Recents';
import ScrollFadeImage from './components/MainBanner';
import bgImage from './img/bg.jpg'; // Adjust your image path';

const pages = {
  dashboard: Dashboard,
  contracts: Contracts,
  documents: Documents,
  analytics: Analytics,
  recents: Recents,
  users: Analytics,
};

const pageConfigurations = {
  dashboard: {},
  contracts: {},
  documents: {},
  analytics: {},
  recents: {},
  users: {},
};

function App() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [activePage, setActivePage] = useState('dashboard');
  const [pageSubTitle, setPageSubTitle] = useState('What should be written in this part');
  const [pageTitle, setPageTitle] = useState('EMALEXPOTS.ph');
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [previousPage, setPreviousPage] = useState(null);
  const [cart, setCart] = useState([]);

  const updatePageConfig = (pageId, config) => {
    pageConfigurations[pageId] = { ...pageConfigurations[pageId], ...config };
  };

  // const setCart = (potId, qty=1) => {
  //   const pot = cart.find(x => x['id'] == potId)
  //   if (pot) {
  //     pot['qty'] += qty;
  //   }
  //   else {
  //     newPot = {'id': potId, 'qty': qty, 'comments': ''}
  //     cart.push(newPot)
  //   }
  // }

  const removeItem = (potId) => {
    const pot = cart.find(x => x['id'] == potId)
    cart.pop(pot);
  }

  const handlePageChange = (pageId, config = null) => {
    if (pageId === activePage && !config) return;
    
    if (config) {
      updatePageConfig(pageId, config);
    }
    
    setPreviousPage(activePage);
    setIsTransitioning(true);
    
    setTimeout(() => {
      setActivePage(pageId);
      setPreviousPage(null);
      setIsTransitioning(false);
    }, 150);
  };

  const PageComponent = pages[activePage];
  const PreviousPageComponent = previousPage ? pages[previousPage] : null;

return (
    <ModalProvider>
      <div className="flex flex-col min-h-screen relative z-0 bg-slate-900 bg-cover bg-center bg-no-repeat bg-fixed"
           style={{ backgroundImage: `url(${bgImage})` }}
      >
        <Header sidebarOpen={sidebarOpen} setSidebarOpen={setSidebarOpen} title={pageTitle} subTitle={pageSubTitle} cart={cart} setCart={setCart} />
        <ScrollFadeImage />
        <div className={`flex flex-1 overflow-hidden transition-all duration-500 ease-in-out ${isTransitioning ? 'min-h-[calc(100vh-80px)]' : ''}`}>
          {/* <Sidebar 
            isOpen={sidebarOpen} 
            onClose={() => setSidebarOpen(false)} 
            activeMenu={activePage}
            onMenuSelect={handlePageChange}
            setTitle={setPageTitle}
            setSubTitle={setPageSubTitle}
          /> */}
          <main className={`h-full dark:bg-gradient-to-r dark:from-gray-900 dark:to-gray-800 flex-1 overflow-hidden relative transition-height duration-500 ease-in-out ${isTransitioning ? 'min-h-[calc(100vh-80px)]' : ''}`}>
            <div className="page-transition-container relative w-full bg-white">
              {/* Previous page (shrink + fade out) */}
              {PreviousPageComponent && (
                <div className={`page-fade-out absolute inset-0 transition-all duration-300 ease-out ${
                  isTransitioning 
                    ? 'opacity-0 scale-[0.97] translate-y-2 h-[90%]' 
                    : 'opacity-100 scale-100 translate-y-0 h-full'
                }`}>
                  <PreviousPageComponent onNavigate={handlePageChange} initialConfig={pageConfigurations[previousPage]} onConfigChange={(config) => updatePageConfig(previousPage, config)} />

                </div>
              )}
              
              {/* Current page (grow + fade in) */}
              <div className={`page-fade-in relative transition-all duration-400 ease-out delay-100 ${
                isTransitioning 
                  ? 'opacity-0 scale-[0.97] -translate-y-2 h-[90%]' 
                  : 'opacity-100 scale-100 translate-y-0 h-full'
              }`}>
                <PageComponent onNavigate={handlePageChange} initialConfig={pageConfigurations[activePage]} onConfigChange={(config) => updatePageConfig(activePage, config)} />

              </div>
            </div>
          </main>
        </div>
        {/* <Footer /> */}
      </div>
    </ModalProvider>
  );

}

export default App;
