  dashboardFilled: Icons.DashboardFilledIcon,
  contractsFilled: Icons.ContractsFilledIcon,
  documentsFilled: Icons.DocumentsFilledIcon,
  analyticsFilled: Icons.AnalyticsFilledIcon,
  userFilled: Icons.UsersFilledIcon,
  plusFilled: Icons.PlusFilledIcon,
  editFilled: Icons.EditFilledIcon,
  deleteFilled: Icons.DeleteFilledIcon,
